const MEASURES = [
  {"id": "1", "pillar": "foundation", "section": "Honouring the Host Nations", "tier": "core", "title": "Standing government-to-government working tables", "body": "<p>Establish quarterly working tables between the City (Mayor + Chief Administrative Officer) and the elected leadership of the Songhees Nation and the Esquimalt Nation respectively. Standing agendas: shared infrastructure, land use, cultural protocols, economic opportunities, public safety coordination. Published meeting summaries (with Nation approval) so residents can see the partnership is real.</p>", "budget": "$150K/year for dedicated municipal staff time and Nations’ capacity support. The largest cost of broken relationships is litigation and stalled projects — prevention is cheap."},
  {"id": "2", "pillar": "foundation", "section": "Honouring the Host Nations", "tier": "core", "title": "Indigenous procurement standard", "body": "<p>Adopt a municipal Indigenous procurement target consistent with the federal 5% standard. Prioritize Songhees and Esquimalt Nation-owned and -affiliated businesses where qualified. Simplify RFP processes for small Indigenous suppliers (single-point-of-contact, plain-language requirements, advance notification of upcoming contracts).</p>", "budget": "Revenue-neutral. The City is already procuring goods and services; we are changing who gets the work, not adding spending."},
  {"id": "3", "pillar": "foundation", "section": "Honouring the Host Nations", "tier": "core", "title": "lək̓ʷəŋən place names and signage", "body": "<p>Continue and accelerate dual-naming of streets, parks, and public buildings using lək̓ʷəŋən place names, with the participation and consent of the Nations. Where there is clear historical record and Nation support, restore Indigenous names that predate colonial ones.</p>", "budget": "$50K/year as part of normal signage lifecycle replacement."},
  {"id": "4", "pillar": "foundation", "section": "Honouring the Host Nations", "tier": "core", "title": "Cultural protocols for City operations", "body": "<p>Adopt clear protocols for Council meetings, civic events, and major project consultations — including territorial acknowledgments developed <em>with</em> the Nations (not generic boilerplate), and Nation participation in major land use decisions affecting their territories.</p>", "budget": ""},
  {"id": "5", "pillar": "foundation", "section": "Honouring the Host Nations", "tier": "core", "title": "Permanent urban Indigenous services liaison", "body": "<p>The City does not deliver social services. But it can coordinate. Establish a permanent municipal liaison position for urban Indigenous services, working with the Victoria Native Friendship Centre, Surrounded by Cedar Child & Family Services, and other organizations to ensure City infrastructure (parks, recreation, libraries, emergency services) is accessible and welcoming for urban Indigenous residents.</p>", "budget": "$120K/year (one FTE plus operating). Substantially offset by reduced friction on consultations and partnerships."},
  {"id": "6", "pillar": "liveable", "section": "Housing: A City Where You Can Live", "tier": "core", "title": "Beat provincial housing targets — with the right composition", "body": "<p>Victoria is already exceeding provincial housing-start targets in raw volume (4,859 starts in 2025 versus a 5-year target of 4,902). The real problem is <strong>composition</strong>: CMHC data shows Victoria building <strong>56 apartments for every single townhouse.</strong> A city where families cannot find 3-bedroom homes is a city that exports young families.</p><p>Targets to 2030, <strong>with quarterly reporting on each:</strong></p><ul><li><strong>12,000+ new homes total</strong> (vs. provincial target of 4,902)</li><li><strong>At least 25%</strong> in the missing middle: townhomes, duplexes, triplexes, fourplexes, garden suites</li><li><strong>At least 20%</strong> as 3-bedroom or larger family-sized units</li><li><strong>At least 15%</strong> as below-market or non-market through partnerships with BC Housing</li><li><strong>At least 30%</strong> as purpose-built rental</li></ul><p>These targets stack: a single building can count toward more than one category. The point is to use the City's land, permit, and zoning levers to shift the <strong>mix</strong>, not just the headline number.</p><p>We will also identify and release city-owned land suitable for housing through a competitive process that scores developers on speed to completion, affordability commitments, and design quality — not just price.</p>", "budget": "Revenue-positive at full build-out. Property tax revenue from 12,000 new units, staged across the term: estimated $8–15M/year in new ongoing revenue by end of 2030, less in early years."},
  {"id": "6b", "pillar": "liveable", "section": "Housing: A City Where You Can Live", "tier": "sub", "title": "City land bank — continue and operationalize the 2022 commitment", "body": "<p>Mayor Alto's 2022 platform committed to establishing a city land bank — using City-owned and acquired land as a strategic instrument for affordable housing, civic infrastructure, and long-term value capture. The commitment has had cross-bloc support, but delivery has been limited. <strong>We will continue this commitment and give it operational discipline.</strong></p><ul><li><strong>Public inventory</strong> of all city-owned land suitable for housing, with parcel-level mapping, current use, and disposition status — published and updated quarterly</li><li><strong>Strategic acquisition fund</strong> for opportunistic purchases (foreclosures, surplus federal/provincial sites, distressed commercial blocks suitable for residential conversion)</li><li><strong>Competitive disposition</strong> that scores proposals on speed to completion, affordability commitments, design quality, and family-sized unit ratio (per Measure 6 composition targets) — not just price</li><li><strong>Right-of-first-refusal</strong> for non-profit and Indigenous-owned housing partners on a published share of disposed parcels</li><li><strong>Quarterly public reporting</strong> on holdings, dispositions, and resulting housing outcomes</li></ul><p>This is a continuation, not a new direction. The objective is to make a started commitment work — not to substitute for it.</p>", "budget": "Inventory platform and audit: $200K one-time. Strategic acquisition reserve: $2–5M initial fund, replenished from dispositions. Long-term: revenue-positive through land-value capture and affordability leverage."},
  {"id": "7", "pillar": "liveable", "section": "Housing: A City Where You Can Live", "tier": "core", "title": "Cut permit processing times by category — publish the numbers", "body": "<p>Victoria currently publishes no permit-processing benchmarks. That ends.</p><p><strong>Published targets by permit type:</strong></p><ul><li><strong>Simple residential building permits</strong> (single-family alterations, secondary suites): from 3–6 months to <strong>under 6 weeks</strong></li><li><strong>Complex building permits</strong> (multi-unit, mixed use): from 12+ months to <strong>under 6 months</strong></li><li><strong>Rezoning applications</strong>: from 12–18+ months to <strong>under 9 months</strong></li><li><strong>Development permits</strong> (form & character, heritage alteration): published targets per category, audited quarterly</li></ul><p><strong>Concrete actions:</strong></p><ul><li><strong>One-stop development centre:</strong> a single physical and digital entry point for all permits</li><li><strong>Online e-permitting with real-time status tracking</strong> — you know exactly where your application stands at all times, like tracking a package</li><li><strong>Published service standards by permit type</strong>, with quarterly variance reports</li><li><strong>AI-assisted pre-screening of permit applications</strong> — software that generates a conformity report flagging issues for human review, on the model that Kelowna is currently developing (<em>ConstructConnect</em>). Kingston's DASH portal provides 24/7 online access with a 10-business-day target on simple permits (<em>Kingston Herald</em>). Kamloops launched paperless permits in November 2024 (<em>Castanet</em>). Victoria publishes no processing benchmarks and offers no comparable digital tools. We will match the best in BC within Year 1</li><li><strong>Statutory deadline review:</strong> Where the BC Local Government Act and Community Charter permit, introduce response-time triggers (e.g., escalation to senior staff, fee waivers for delayed files). Where statute restricts automatic advance, publish accountability metrics instead. The point is consequences for City delay, not lawlessness</li><li><strong>Simplify and clarify zoning rules.</strong> When rules are 2,000 pages long, even experts get lost. Clear rules mean faster approvals, fewer appeals, and less uncertainty for builders. The VRBA consistently criticizes Victoria's \"regulatory hurdles, slow approval processes, and escalating fees\" (<em>VRBA</em>)</li></ul>", "budget": "~$700K/year for e-permitting platform, AI pre-screening tools, and additional intake staff. Offset by faster file processing and a 4–6 FTE reduction in manual review over 3 years (~$400K–600K/year savings). Net: roughly neutral, with massive economic benefit from faster housing delivery."},
  {"id": "8", "pillar": "liveable", "section": "Housing: A City Where You Can Live", "tier": "core", "title": "Push vacancy rate to 5%", "body": "<p>A healthy market where renters have real choices. The vacancy rate has already risen from 1.6% (2023) to 3.3% (2025) — the highest in 26 years (<em>Victoria News</em>) — largely due to factors outside City control (reduced immigration, weak youth employment). But this progress is fragile. We must lock it in by continuing to accelerate supply, so the next economic cycle doesn't plunge us back into a crisis.</p><p><strong>Concrete actions:</strong></p><ul><li>Accelerate purpose-built rentals, garden suites, duplexes, triplexes, and infill housing across appropriate zones</li><li>Pre-zone residential areas for missing-middle housing — no rezoning hearings needed for duplexes and triplexes in single-family zones</li><li>Targeted DCC reductions for purpose-built rental projects, paired with a published infrastructure funding plan so the cuts do not strand essential infrastructure spending</li><li>Expedited permits for any project delivering below-market rental units</li></ul>", "budget": ""},
  {"id": "9", "pillar": "liveable", "section": "Housing: A City Where You Can Live", "tier": "core", "title": "Protect tenants from demoviction", "body": "<p><strong>The problem:</strong> Redevelopment is essential to grow housing supply (Measure 6), but redevelopment without tenant protection creates churn that destabilizes neighbourhoods and prices long-time renters out of the city. The goal is more housing AND fewer displacements — not one or the other.</p><p><strong>What we will do:</strong></p><ul><li><strong>Stronger controls when buildings are redeveloped</strong> — minimum notice periods (12+ months for major redevelopment), moving-cost compensation indexed to local rents, and a documented right-of-return for displaced tenants</li><li><strong>Mandatory replacement rental units</strong> — buildings that displace rental tenants must replace those units in the new development at a documented ratio, with priority access for displaced tenants at a published below-market rate</li><li><strong>Renters' Hub</strong> — a single digital and physical front door for tenant rights information, continuing the existing partnership with the Tenant Resource and Advisory Centre and on the Coun. Krista Loughton / Coun. Dave Thompson 2025 motion concept. Plain-language guides on RTA process, sample letters, direct referral to legal aid</li><li><strong>Tenant assistance program during transitions</strong> — case management for vulnerable tenants (seniors, people with disabilities, language-barrier) facing displacement</li><li><strong>Coordinate with provincial enforcement</strong> — the Residential Tenancy Branch and the Compliance and Enforcement Unit handle most landlord-tenant disputes; the City's role is information, support, and aggressive advocacy for stronger provincial enforcement (per Measure 70b)</li></ul><p>More housing, not fewer tenants. Growth and protection go together.</p>", "budget": "$200K/year for Renters' Hub operations and case management. Largely revenue-neutral on enforcement (provincial jurisdiction). Significant indirect savings: a tenant who is helped to stay in their unit is a tenant who does not enter the homelessness pipeline (Measure 11)."},
  {"id": "9b", "pillar": "liveable", "section": "Housing: A City Where You Can Live", "tier": "sub", "title": "Short-term rental licensing — protect the long-term rental pool", "body": "<p>Tighten short-term rental (STR) licensing, enforcement, and platform-data reporting. STRs convert long-term rental units into part-time tourist accommodation, tightening vacancy in exactly the moment we are working to expand it. Within the BC framework, the City will: require platform-side licence display and data sharing on every listing; cap non-principal-residence STRs; cross-reference STR addresses against business licence and property tax records; impose meaningful penalties for unlicensed operation that escalate per offence; publish a quarterly STR compliance report by neighbourhood.</p><p><em>This measure addresses residential rental supply. The related but separate problem of commercial downtown storefront vacancy is handled under Measure 71.</em></p>", "budget": "$200K/year for an STR compliance officer + platform-data audit tools. Self-funding through licensing fees and penalty revenue within 2 years."},
  {"id": "9c", "pillar": "liveable", "section": "Housing: A City Where You Can Live", "tier": "sub", "title": "Advocate for vacancy control between tenancies", "body": "<p>Vacancy control between tenancies — limiting rent resets to tied-to-unit rather than tied-to-tenant — is provincial jurisdiction under the Residential Tenancy Act. The City does not control it. But the City can be a credible advocate. Council will pass a formal advocacy resolution calling on the Province to introduce inter-tenancy rent control on the model of Manitoba and parts of Quebec, conditional on offsetting protections for landlord operating-cost recovery so that maintenance investment is preserved.</p>", "budget": "$0 (advocacy only). Real impact requires provincial action."},
  {"id": "10", "pillar": "liveable", "section": "Housing: A City Where You Can Live", "tier": "core", "title": "Transparent housing allocation — digital, rules-based, no queue-jumping", "body": "<p>Modernize social housing waitlist coordination with a clear, digital process inspired by the best allocation systems in the world.</p><p><strong>How it works (within municipal authority — BC Housing remains the social housing operator):</strong></p><ul><li><strong>A single digital portal</strong> for City-affiliated waitlists and partner non-profits: upload your documents once. No more filling out multiple applications at different providers</li><li><strong>Transparent point-based scoring:</strong> criteria are public and rational. Sample weights: working in Victoria (+50), essential worker in healthcare/childcare/emergency services (+20), single parent (+20), disability in the household (+50), family with 3+ children (+10), time on waitlist (+1 per month, max 10)</li><li><strong>Real-time visibility:</strong> you see your position in the queue, the number of units available, the number of units coming available in the next months, and your probability of receiving an offer</li><li><strong>No outside intervention possible.</strong> No queue-jumping, no political favours. The algorithm assigns based on points</li><li><strong>Alerts:</strong> you receive a notification when a unit matching your criteria becomes available. You accept or decline. After three declines, you are moved to the back of the queue</li></ul><p>This replaces opaque processes with full transparency. It also optimizes occupancy — matching partial-week needs, flagging units sitting vacant, and maximizing the use of every available space.</p>", "budget": "$250K for platform development and maintenance. Savings of 3–5 FTEs in manual waitlist administration (~$300K–500K/year). Net: $50K–250K/year savings, with dramatically better service."},
  {"id": "11", "pillar": "liveable", "section": "Housing: A City Where You Can Live", "tier": "core", "title": "Reduce unsheltered homelessness by 50%", "body": "<p><strong>Currently:</strong> The Alto council has spent <strong>$25M+ on homelessness response since 2023</strong> without publishing outcome metrics, plus <strong>$11M repairing encampment damage</strong>. The 2025 Point-in-Time count found 1,749 people experiencing homelessness across the Capital Region, up from 1,665 in 2023 (<em>Globe and Mail</em>). The Community Safety and Well-Being plan was not endorsed until June 2025 — nearly three years into the term — and its Phase 1 was funded by raiding reserves rather than by operational savings.</p><p><strong>ACTW:</strong> Reduce unsheltered homelessness by 50% — from ~320 to under 160 — through Housing-First: supportive housing with wraparound mental health and addiction services, in partnership with BC Housing and local non-profits. <strong>With published outcome metrics, not just dollars spent.</strong></p><p>This is not about enforcement alone — it is about offering genuine alternatives and then enforcing consistently. You cannot enforce people off the streets if there is nowhere for them to go. We build capacity first, then enforce.</p><p>Victoria bears a <strong>vastly disproportionate regional burden</strong>: 89% of shelter beds and 83% of supportive housing for the entire Capital Region, despite being one of 13 municipalities. Since 2017, the Province has funded 4,120+ homes in Victoria through BC Housing, with major projects like the 158-unit tower at 926–930 Pandora and 90 supportive units at 726 Discovery Street (<em>BC Gov News</em>). <strong>We will continue and accelerate these provincial partnerships</strong> — they are working. We will demand the other 12 municipalities take their fair share — and we will hold the Province accountable for every dollar spent by publishing outcomes, not just inputs.</p><p><strong>Throughput, not just intake — adopt a STEP-style program.</strong> Supportive housing in Victoria is effectively full at all times, even as people remain unsheltered. The bottleneck is <em>throughput</em>: residents who have stabilized are not transitioning out to market or non-market housing, so units stay occupied and new entrants have nowhere to go. On the Coun. Krista Loughton January 2026 motion and the Vancouver Streetohome / BC Housing / Vancouver Coastal Health STEP (Supporting Tenants, Enabling Pathways) model, the City will partner with BC Housing, Island Health, and Pacifica Housing to operate a transition program: case-managed pathway from supportive housing → bridging non-market rental → market rental, with maintained service connection through each step. Free up the supportive units; do not just add to them. Coordinated Access and Assessment (per the June 2025 Loughton/Thompson motion) is the intake side; STEP is the exit side. Both are required.</p>", "budget": "City's share estimated at $2–3M/year above current spending. Offset partially by reduced emergency-services costs ($11M in encampment damage repair would be dramatically reduced) and bylaw enforcement burden (currently consuming 80% of officer time). Requires provincial co-funding for supportive housing operations."},
  {"id": "12", "pillar": "liveable", "section": "A City That Works for Families", "tier": "core", "title": "Advocate aggressively for 500 new childcare spaces", "body": "<p>Childcare is provincially regulated, but the City controls zoning, permits, and city-owned buildings. We will use every municipal lever available:</p><ul><li><strong>Fast-track permits for childcare facilities</strong> — any new childcare centre application processed in 60 days or less</li><li><strong>Pre-zone community buildings, churches, and commercial spaces for childcare use</strong> — eliminate the rezoning step that adds 6–12 months</li><li><strong>Offer city-owned space at below-market rates to licensed childcare operators</strong> — we have community centres and buildings that are underused during daytime hours</li><li><strong>Advocate to the Province for priority housing for Early Childhood Educators</strong> — ECE workers earn $20–25/hour but cannot afford to live in the city where they work. If they can't afford to live here, they don't work here, and your children don't have childcare</li></ul>", "budget": "$300K/year in foregone lease revenue from city-owned spaces. Offset by increased labour force participation of parents (more property and business tax revenue). Advocacy to Province: $0 direct cost."},
  {"id": "13", "pillar": "liveable", "section": "A City That Works for Families", "tier": "core", "title": "Improve school food quality", "body": "<p>Victoria's school food programs should serve local, BC-sourced ingredients wherever possible. We will:</p><ul><li>Work with School District 61 to establish a \"Farm to School\" standard for school meal programs, prioritizing Vancouver Island producers</li><li>Partner with local chefs to redesign cafeteria menus — real food, made fresh, that children actually want to eat</li><li>Publish daily meal photos on school communication apps — parents see exactly what their children are served</li></ul><p>This is not the City's direct jurisdiction (education is provincial), but the City can convene, co-fund, and champion. It costs little and delivers enormous community goodwill.</p>", "budget": "$150K/year in City co-funding for local procurement premium. Leverages existing School District and provincial nutrition program budgets."},
  {"id": "13b", "pillar": "liveable", "section": "A City That Works for Families", "tier": "sub", "title": "Recruit family doctors with low/no-rent clinic space + permissive tax exemption", "body": "<p>Victoria, like much of BC, faces an acute family-doctor shortage. Healthcare is provincial jurisdiction, but the City controls property tax, zoning, and municipal real estate — three levers that materially affect where clinics can afford to operate. On the precedent of the Andrew 2022 platform plank and the Alto 2022 \"permissive tax exemptions for not-for-profit clinics\" commitment (still not delivered), the City will:</p><ul><li><strong>Permissive tax exemptions for not-for-profit primary care clinics</strong> under section 224 of the Community Charter, on the precedent of similar exemptions for not-for-profit social service providers</li><li><strong>Below-market lease of city-owned or city-affiliated space</strong> to recruited family practices, with affordability and bulk-billing conditions</li><li><strong>Fast-track permitting</strong> for new clinic builds and conversions, on the same timeline as childcare facilities (Measure 12)</li><li><strong>Co-funded recruitment partnership</strong> with Island Health and the Province for family doctors willing to commit to Victoria for a minimum term</li></ul>", "budget": "Foregone property tax and lease revenue: $200–400K/year at full uptake. Direct return is a healthier, more productive resident base; family-doctor access correlates strongly with reduced emergency-room utilization and is a top citable factor in resident retention surveys."},
  {"id": "13c", "pillar": "liveable", "section": "A City That Works for Families", "tier": "sub", "title": "Reach Victoria's young adults (18–25)", "body": "<p>Victoria's families and seniors are reasonably well-served by existing City programming. Its <strong>young adults</strong> — particularly those aging out of school programs, transitioning to independent housing, or new to the city for work or post-secondary education — are not. The result is out-migration of exactly the demographic the city depends on for its future.</p><p>The City does not deliver youth services directly (BC and federal jurisdiction), but it controls space, programming budgets, and partnerships:</p><ul><li><strong>Youth-priority slots in below-market City-owned and -leased space</strong> for organizations serving 18–25 — including the Victoria Native Friendship Centre's youth programming, employment-training partners, and post-secondary partnership programs</li><li><strong>Late-evening recreation and community-centre hours</strong> in dedicated facilities, priced for off-peak access (free or near-free)</li><li><strong>Youth fare partnership</strong> with BC Transit — work toward continuation and expansion of existing youth and student fare structures</li><li><strong>Annual Youth Voice consultation</strong> with measurable response standards (per Measure 79) and youth representation on advisory committees affecting their neighbourhoods</li><li><strong>Co-investment with Camosun, UVic, and Royal Roads</strong> on student-housing and student-employment partnerships rooted in Victoria proper</li></ul>", "budget": "$200–300K/year for youth-priority space, late-hours operations, and consultation. Leverages existing School District, post-secondary, and provincial programming budgets at significant multiplier."},
  {"id": "14", "pillar": "liveable", "section": "A Clean City", "tier": "core", "title": "90% of graffiti removed within 48 hours", "body": "<p>Rapid-response cleaning crews, expanded DVBA Clean Team contracts, real-time dispatch through the ConnectVictoria app. Establish this as a published service standard, tracked and reported quarterly.</p><p><strong>Continuing the DVBA partnership.</strong> The DVBA Clean Team removes over 12,000 graffiti tags per year — it is one of the most effective public-realm partnerships the City has. We will continue and expand the partnership, not replace it. The 48-hour standard is the discipline; the partnership is how we deliver it.</p>", "budget": ""},
  {"id": "15", "pillar": "liveable", "section": "A Clean City", "tier": "core", "title": "Competitive bidding for waste collection and street cleaning", "body": "<p><strong>Currently:</strong> Victoria's roughly $12M/year in waste collection and street cleaning operates without any competitive benchmarking. The City does not know whether it pays market rates because it has never tested the market.</p><p><strong>ACTW:</strong> Cities that have introduced competitive bidding for waste collection and street cleaning have delivered substantial multi-year savings while improving service quality. <strong>Phoenix's managed competition program saved the city in excess of $25 million between 1978 and 1988 alone</strong> (<em>Frontier Centre for Public Policy, citing City of Phoenix Public Works records</em>) — the model is mature, well-documented, and has been adopted across North America. The private sector's core business is logistics and cleaning; their survival depends on better equipment, better routing, and better training.</p><p><strong>How we will do it:</strong></p><ul><li>Divide Victoria into zones and issue competitive tenders for each zone</li><li>Require bidders to meet strict performance standards: response times, cleanliness scores, citizen satisfaction surveys</li><li><strong>Include employee protection clauses:</strong> at least 80% of existing City workers in these roles must be offered equivalent positions at equal or higher pay by winning bidders</li><li>The City retains oversight and audits performance quarterly. If a contractor underperforms, the contract can be terminated and re-tendered</li><li>Consider a <strong>\"managed competition\"</strong> model on the Phoenix precedent: City workers bid against private firms in their own tender. This kept services public when public delivery was competitive (<em>GovTech</em>)</li></ul><p>This is not ideology — it is the same approach that has worked in cities across Canada and internationally. The CRD's own blue-box recycling is already contracted to GFL Environmental — the principle is proven regionally.</p>", "budget": "Current waste and street cleaning costs: ~$12M/year. Expected savings at 20% (a conservative target consistent with documented multi-year programs elsewhere): <strong>$2.4M/year.</strong> Workers protected. Service improved. Savings redirected to frontline priorities, including the funded source for extended bylaw hours (Measure 27)."},
  {"id": "16", "pillar": "liveable", "section": "A Clean City", "tier": "core", "title": "Anti-rat and pest management plan", "body": "<p>Rat proliferation is a direct consequence of poor sanitation. The best anti-rat measure is removing food sources at street level.</p><ul><li>Locking lids on commercial waste bins — bins that open only when tipped by collection trucks</li><li>QR codes on public waste bins: residents scan to report a full bin, and crews are dispatched in real time</li><li>Dedicated pest control team using modern methods: dry ice, smart traps, grate covers on storm drains</li><li>Coordination with restaurant and food service operators on waste storage standards</li></ul>", "budget": "$200K/year for enhanced pest management. QR bin system: $50K setup, $20K/year maintenance. Offset by reduced property damage and health complaints."},
  {"id": "17", "pillar": "liveable", "section": "A Clean City", "tier": "core", "title": "Extended sanitation hours", "body": "<p>Daily street sweeping and bin emptying in the downtown core, including evenings and weekends. Clean when it matters, not just during office hours.</p>", "budget": ""},
  {"id": "18", "pillar": "liveable", "section": "A Clean City", "tier": "core", "title": "Community pride — replace graffiti with public art", "body": "<p>Expand the \"My Great Neighbourhood\" grants for community gardens, murals, and block clean-ups. Commission neighbourhood-specific murals and installations — art that tells Victoria's story: lək̓ʷəŋən history, maritime heritage, natural beauty. Neighbourhoods that take ownership stay clean.</p>", "budget": ""},
  {"id": "19", "pillar": "liveable", "section": "A City Where You Can Get Around", "tier": "core", "title": "Adaptive traffic signal control on major corridors", "body": "<p>Progressively, traffic signals on Victoria's major corridors will be connected to an adaptive control system that adjusts signal timing in real time based on:</p><ul><li><strong>Local conditions at each intersection:</strong> if a queue threatens to block an adjacent intersection, the light stays green longer to prevent the bottleneck from spreading</li><li><strong>Corridor-level conditions:</strong> detecting congestion patterns, identifying streets to relieve, holding access roads at red longer to prevent saturation of main arteries</li><li><strong>Continuous learning:</strong> the more the system observes traffic patterns and driver behavior, the better it optimizes</li></ul><p>Pittsburgh's Surtrac adaptive control system, deployed at ~50 intersections, reduced travel times by 25% and emissions by 21% (<em>Carnegie Mellon Robotics Institute</em>). A 2024 study published in <em>Nature</em> of 100 cities with adaptive signals found an 11% average reduction in travel time during peak hours, 8% off-peak, with Boston reporting 13.5%.</p><p><strong>Realistic phased rollout:</strong></p><ul><li><strong>Year 1: Pilot of 10 intersections</strong> on the Douglas Street corridor, fully instrumented (controllers, detection, fibre/wireless backhaul, central software): <strong>$1.5–2M</strong></li><li><strong>Year 2–3: Evaluate pilot, then expand to 30–40 additional intersections on major corridors</strong> (Hillside, Blanshard): <strong>$3–4M</strong></li><li><strong>Year 4: Optionally extend to remaining major corridors</strong> based on measured results: <strong>$2–3M</strong></li></ul>", "budget": "Total investment over 4 years: <strong>$6–9M</strong> (revised from earlier estimates to reflect realistic per-intersection costs of $30K–100K including controller, detection, backhaul, software, and integration — not sensors alone). Annual maintenance: $300K/year at full deployment. Savings in commuter time and fuel: significant but hard to quantify. Reduction in emissions: measurable and reportable. <strong>Critical:</strong> do not proceed to Phase 2 without measured outcomes from Phase 1 against published baselines."},
  {"id": "20", "pillar": "liveable", "section": "A City Where You Can Get Around", "tier": "core", "title": "Complete the All Ages & Abilities bike network", "body": "<p>Close gaps in the 36 km built so far, extend protected lanes into neighbourhoods, improve bike parking and end-of-trip facilities. Physical separation from traffic — not painted lines. Victoria has the cycling culture; we need the infrastructure to match.</p>", "budget": ""},
  {"id": "21", "pillar": "liveable", "section": "A City Where You Can Get Around", "tier": "core", "title": "Modernize transit fare payment", "body": "<p>Work with BC Transit to finally deliver contactless payment (credit, debit, mobile). Free Wi-Fi on buses and at hubs. This is table stakes for a modern transit system — Victoria is behind every comparable Canadian city.</p>", "budget": ""},
  {"id": "22", "pillar": "liveable", "section": "A City Where You Can Get Around", "tier": "core", "title": "Champion Westshore rapid transit and the E&N corridor", "body": "<p>A growing proportion of Victoria's daytime workforce lives in Langford, Colwood, and View Royal. Peak commutes routinely exceed 60 minutes one way. The City of Victoria does not control inter-municipal transit (that is BC Transit and provincial jurisdiction), but it sits at the geographic and political centre of the region and benefits massively from a functional regional network.</p><p><strong>Cross-bloc municipal work.</strong> Regional transit on the Westshore corridor is one of the rare points of multi-councillor and cross-municipality alignment — Coun. Jeremy Caradonna's CRD vice-chair role on regional housing connects to it, Mayor Alto's 2026 \"reimagine transportation\" plank touches it, and the Westshore mayors (Stewart Young in Langford, Doug Kobayashi in Colwood, Karen Harper in View Royal) have all signalled support in principle. Victoria's job is to refuse to be the regional bottleneck.</p><p><strong>The City will:</strong></p><ul><li><strong>Formally endorse Light Rail or Bus Rapid Transit on the E&N corridor</strong> as the highest-priority regional transit investment, and request acceleration of the Province's South Island Transportation Strategy</li><li><strong>Protect the E&N right-of-way for transit use</strong> within Victoria's boundaries through zoning and infrastructure decisions — no encroachment that forecloses future rail or BRT operation</li><li><strong>Co-fund station-area planning</strong> with the CRD and Westshore municipalities so that when provincial funding arrives, receiving infrastructure is ready</li><li><strong>Provide dedicated bus lanes on Douglas Street and Trans-Canada approaches</strong> to keep RapidBus 95 competitive with driving in the meantime</li><li><strong>Use the working table with the host Nations</strong> (Measure 1) to ensure E&N planning respects treaty and reserve geography from day one, not as an afterthought</li></ul><p>A functional Westshore connection takes pressure off Victoria's own housing market, supports downtown employers, and reduces the carbon and congestion costs of single-occupancy commuting. The City cannot build it alone, but it can refuse to be the bottleneck.</p>", "budget": "$300K/year for dedicated transportation planning staff and CRD / provincial co-funding contributions. Long-term capital is provincial / federal."},
  {"id": "23", "pillar": "liveable", "section": "A City Where You Can Get Around", "tier": "core", "title": "Expand RapidBus and dedicated bus lanes", "body": "<p>Make transit time-competitive with driving on Douglas, Hillside, and other major corridors. If the bus is faster than the car, people will take the bus. If it isn't, they won't.</p>", "budget": ""},
  {"id": "24", "pillar": "liveable", "section": "A City Where You Can Get Around", "tier": "core", "title": "Parking that supports business — rational pricing, real-time data", "body": "<p><strong>First-hour free parking in commercial areas.</strong> When you want to pop into a shop, grab a coffee, or pick up takeout, you shouldn't pay $3–5 just to park for 20 minutes. A free first hour supports local business, encourages foot traffic, and increases turnover.</p><p><strong>Real-time parking availability.</strong> Approximately 30% of downtown traffic is drivers who have reached their destination but are circling for a spot. We will use existing camera infrastructure and computer vision to identify available parking spaces and publish this data through the City's open data portal and integrations with major navigation apps. Less circling means: less traffic, less pollution, less noise, less wasted fuel, less frustration.</p>", "budget": "First-hour free: estimated $1.5–2.5M/year in foregone meter revenue (verified against actual downtown meter revenue, not the smaller estimate cited in some previous plans). Partially offset by increased commercial activity, business licence revenue, and turnover. Real-time parking system: $300K setup, $80K/year maintenance. <strong>Note:</strong> Direct sale of parking-availability data to navigation platforms is not a reliable revenue stream (mapping platforms derive parking signals from device telemetry, not municipal feeds). We do not budget revenue from data licensing."},
  {"id": "24b", "pillar": "liveable", "section": "A City Where You Can Get Around", "tier": "sub", "title": "Public bathrooms as transportation infrastructure", "body": "<p>On the Coun. Susan Kim 2022 platform plank: a city that asks residents and visitors to walk, cycle, take transit, and spend time in its public spaces must provide the basic dignity of a place to use a bathroom. Victoria's current network is sparse, poorly mapped, and inconsistently maintained — a daily problem for seniors, families with young children, people with medical conditions, transit users on long trips, and the vulnerable residents the city is trying to bring indoors.</p><ul><li><strong>Network expansion:</strong> at least one publicly-accessible 24/7 washroom every 500 metres in the downtown core, Inner Harbour, and major commercial corridors (Government, Douglas, Fort, Cook)</li><li><strong>Modern format mix:</strong> attended facilities where viable, automated kiosks (Sanisette-style) where attended is not</li><li><strong>Real-time location and status</strong> integrated with the ConnectVictoria app and open data portal (per Measure 56)</li><li><strong>Daytime extended access partnership</strong> with businesses and the DVBA in commercial areas</li><li><strong>Universal-design standard:</strong> every new facility built accessible to people with mobility devices, families with strollers, and people of all body sizes</li></ul><p>This is not a luxury. It is basic public-realm infrastructure. The DVBA Clean Team currently spends hundreds of hours per year on the consequences of insufficient facilities — a direct cost that disappears when the underlying need is met.</p>", "budget": "$400–600K/year operating at full deployment. $1.5–2M capital over the term for new units. Substantially offset by reduced sanitation calls and improved public-realm cleanliness scores (Measure 14)."},
  {"id": "25", "pillar": "liveable", "section": "A City Where You Can Get Around", "tier": "core", "title": "Fix roads first", "body": "<p>Prioritize the infrastructure maintenance backlog. Pothole repair targets: report-to-fix within 7 days. Road condition improvements tracked quarterly. Stop building new things while the old things crumble.</p>", "budget": ""},
  {"id": "25b", "pillar": "liveable", "section": "A City That Works for Every Body", "tier": "sub", "title": "Universal accessibility audit and remediation program", "body": "<p>Treat accessibility as a city-wide infrastructure standard, not a one-off project.</p><ul><li><strong>Comprehensive accessibility audit</strong> of all City-owned sidewalks, public buildings, parks, washrooms, and transit-adjacent infrastructure over 24 months — using a published methodology (Rick Hansen Foundation Accessibility Certification or equivalent) and a public dashboard</li><li><strong>Remediation backlog</strong> funded as a dedicated annual capital line, prioritized by foot-traffic and population-density of residents with disabilities</li><li><strong>Universal-design standard</strong> for all new City builds and major renovations — best-practice, not minimum-code</li><li><strong>Curb cut, tactile paving, and audible-signal program</strong> at every controlled intersection within 4 years</li><li><strong>Sidewalk maintenance standard:</strong> response time for hazards and obstructions that disproportionately affect people with mobility devices</li><li><strong>Disability Advisory Committee with delegated review authority</strong> on major projects, integrated into the 5-step process (Measure 78)</li><li><strong>Accessibility lens</strong> required on all permitting and grant decisions</li></ul>", "budget": "Audit: $300K one-time. Remediation capital: $2–3M/year as a dedicated line, partially eligible for the federal Enabling Accessibility Fund and provincial co-funding. Disability Advisory Committee operating: $80K/year. The cost of inaccessibility — reduced participation, lawsuits, retrofit-after-build — is consistently higher than the cost of doing it right."},
  {"id": "26", "pillar": "safe", "section": "Strengthen Public Safety", "tier": "core", "title": "Create a Downtown Public Order Team (DPOT)", "body": "<p><strong>Currently:</strong> Public safety responses across VicPD, Bylaw, Public Works sanitation, and Outreach operate in silos. There is no unified command, no shared daily metrics, no single field supervisor per shift. The Alto council's CSWB plan added staff but did not change the operational structure.</p><p><strong>ACTW:</strong> One unified operation: VicPD + Bylaw + Public Works sanitation + Outreach workers. Single daily briefing at 8 AM, single set of weekly metrics, single field supervisor per shift. No more silos.</p><p>This is the same principle that made the Olympic Games safe in every host city: unified command, constant presence, systematic intervention. There is no reason Victoria cannot have that level of coordination every day.</p><p><strong>DPOT Weekly Dashboard:</strong></p><p><table fit-page-width=\"true\" header-row=\"true\"></p><p><tr></p><p><td>Category</td></p><p><td>KPI</td></p><p><td>Why It Matters</td></p><p></tr></p><p><tr></p><p><td>Encampments</td></p><p><td># downtown encampments removed same-day</td></p><p><td>Visible order</td></p><p></tr></p><p><tr></p><p><td>Response</td></p><p><td>Median time from report → attendance</td></p><p><td>Accountability</td></p><p></tr></p><p><tr></p><p><td>Sidewalks</td></p><p><td># sidewalk obstructions cleared</td></p><p><td>Access/safety</td></p><p></tr></p><p><tr></p><p><td>Parks compliance</td></p><p><td>% shelters down by 7 AM in designated parks</td></p><p><td>Enforce existing rules</td></p><p></tr></p><p><tr></p><p><td>Public drug use</td></p><p><td># enforcement actions + referrals</td></p><p><td>Matches top concern</td></p><p></tr></p><p><tr></p><p><td>Needles</td></p><p><td># needles collected + hotspot map</td></p><p><td>Harm reduction + cleanliness</td></p><p></tr></p><p><tr></p><p><td>Outreach</td></p><p><td># placements to shelter/detox/services</td></p><p><td>Prevent churn</td></p><p></tr></p><p><tr></p><p><td>Crime focus</td></p><p><td># trafficking/weapon/violent-file actions</td></p><p><td>Target disorder drivers</td></p><p></tr></p><p></table></p>", "budget": ""},
  {"id": "27", "pillar": "safe", "section": "Strengthen Public Safety", "tier": "core", "title": "Extend bylaw enforcement to 6 AM – 10 PM, 7 days a week", "body": "<p><strong>Currently:</strong> Bylaw enforcement operates <strong>7 AM – 4 PM weekdays only</strong> — missing the evenings and weekends when disorder actually peaks. The Alto council's CSWB Phase 1 added 12 bylaw staff but did not change the hours; <strong>80% of officer time is consumed by encampment management</strong> rather than general enforcement.</p><p><strong>ACTW:</strong> Extend bylaw enforcement to <strong>6 AM – 10 PM, 7 days a week</strong> — the hours when downtown is actually busy. Funded primarily by managed-competition savings on waste collection (Measure 15: ~$2.4M/year) — not by raising taxes or raiding reserves.</p>", "budget": "$1–1.5M/year for additional bylaw officer shifts (revised upward to reflect collective agreement overtime/shift premiums). Funded primarily by managed competition savings on waste collection ($2.4M/year) — not by raiding reserves or raising taxes. Partially offset further by increased fine revenue and reduced cleanup costs from faster intervention."},
  {"id": "28", "pillar": "safe", "section": "Strengthen Public Safety", "tier": "core", "title": "Target chronic disorder drivers with data", "body": "<p><strong>The problem:</strong> A small number of individuals and locations account for a disproportionate share of downtown disorder calls. Coun. Stephen Hammond's 2023 FOI on VicPD call data surfaced that <strong>~24% of all 2022 police calls came from just 19 identified addresses</strong> — encampments and supportive-housing sites. Spreading enforcement evenly across the city misallocates VicPD's already-stretched capacity (50–55 officers short of authorized strength).</p><p><strong>What we will do:</strong></p><ul><li><strong>Focused-deterrence model</strong> on trafficking, weapons, and violent repeat offenders — coordinated with Crown counsel on bail decisions, sentencing requests, and conditions of release</li><li><strong>Data-driven hotspot identification</strong> updated weekly via the DPOT dashboard (Measure 26), with aggregate locations published quarterly (privacy-protected, no individual identification)</li><li><strong>Crown coordination</strong> on prolific offenders — pre-charge consultations, joint case management, consistent applications for conditions that reduce reoffending</li><li><strong>Outreach decoupled from enforcement</strong> for everyone else — vulnerable people in crisis get the wraparound response (Measure 11, Measure 26 outreach component), not the criminal-justice response</li><li><strong>Refusal-rate tracking</strong> (from Measure 35) identifies residents who decline services and may need a different intervention model</li></ul><p>The principle: <strong>relentless with the dangerous, compassionate with the vulnerable.</strong> These are not the same people, and they should not receive the same response.</p>", "budget": "Within existing VicPD operating envelope; no new officer FTEs. Coordination capacity may require 0.5 FTE Crown-liaison position ($100K/year)."},
  {"id": "28b", "pillar": "safe", "section": "Strengthen Public Safety", "tier": "sub", "title": "Business-security cost-spreading pilot — exposure-based, not blanket", "body": "<p>Pandora-corridor businesses and other disorder-exposed properties carry an enforcement burden the rest of the city does not. Insurance claims, broken glass, private security retainers, sharps removal — these are real costs paid by a small number of property owners. On the Hammond July 2023 motion concept (defeated 6-2 at the time, but the underlying problem is unresolved), the City will pilot a narrow, exposure-based cost-spreading instrument:</p><ul><li><strong>Eligibility:</strong> street-front commercial premises within designated high-exposure zones, defined by FOI-validated VicPD call-volume and Bylaw incident data (Hammond's 2023 FOI surfaced that ~24% of all 2022 police calls came from 19 identified addresses)</li><li><strong>Reimbursement:</strong> capped per-premises reimbursement for specific eligible costs (private security hours, glazing repair, sharps-bin servicing) above a deductible</li><li><strong>Sunset:</strong> 24 months, with renewal contingent on measurable downtown disorder reduction (Measure 32)</li><li><strong>Funded from:</strong> managed competition savings (Measure 15), not new tax revenue</li></ul>", "budget": "$500–800K/year for 24 months as a pilot, funded by reallocation. Sunset clause ensures the program does not become permanent if Phase A/B/C measures succeed."},
  {"id": "29", "pillar": "safe", "section": "Strengthen Public Safety", "tier": "core", "title": "Resolve the VicPD funding dispute with Esquimalt", "body": "<p>Victoria pays <strong>86.33% of the joint VicPD budget</strong>; Esquimalt pays the remainder. Disputes have escalated to provincial appeals. This is dysfunctional governance: it consumes management attention, weakens the Police Board's ability to plan, and undermines public confidence in policing.</p><p><strong>Resolution path:</strong></p><ul><li>A renegotiated funding formula based on transparent service-consumption metrics (calls for service, officer-hours, geography), reviewed every 4 years</li><li>If the parties cannot agree, formal mediation through the BC Police Services Branch with a binding outcome</li><li>Until resolution, publish quarterly the actual service consumption split versus the funding split, so residents in both municipalities can see what they are paying for</li></ul><p>The annual public dispute serves neither Victoria nor Esquimalt residents. A four-year cycle with binding mediation creates predictability for both.</p>", "budget": "$0 to $1.5M/year depending on negotiated outcome. The principle: pay for the service consumed, full transparency on both sides."},
  {"id": "29b", "pillar": "safe", "section": "Strengthen Public Safety", "tier": "sub", "title": "Greater Victoria regional policing services review — binding mediation outcome", "body": "<p>The Capital Region operates <strong>four separate municipal police forces</strong> (VicPD, Saanich, Oak Bay, Central Saanich) plus RCMP detachments — for a region of roughly 400,000 people. Other Canadian metro areas of this scale and smaller operate one integrated service. The cost duplication (four command structures, four IT systems, four procurement streams, four collective agreements) is real and structural. Mayor Alto's May 2026 re-election platform raised regional policing consolidation as a priority; this measure absorbs that plank and gives it a concrete delivery mechanism.</p><p>A <strong>Greater Victoria Policing Services Review</strong> — co-sponsored by Victoria, Saanich, Esquimalt, Oak Bay, View Royal, and the affected First Nations — will:</p><ul><li>Examine operational consolidation, joint-service expansion, or full amalgamation of municipal policing across the region</li><li>Be <strong>time-boxed to 18 months</strong> with terms of reference signed by all participating councils up front</li><li>Produce a costed recommendation with a published deliberative trail (modelled on the BC Police Act framework)</li><li>Trigger <strong>binding mediation through the BC Police Services Branch</strong> if participating jurisdictions cannot agree on a path forward within 6 months of the report</li><li>Preserve municipal accountability through a regional governance structure — not a provincial takeover</li></ul><p>This is a co-sponsorship plank, not a unilateral one. Victoria cannot impose this; Victoria can convene it.</p>", "budget": "$300–500K Victoria share of an 18-month independent review, partially recoverable from participating municipalities. Long-run savings from consolidation, where feasible, are in the millions per year — but the up-front commitment is to the <em>process</em>, not a predetermined outcome."},
  {"id": "30", "pillar": "safe", "section": "Strengthen Public Safety", "tier": "core", "title": "Modern smart streetlighting — Kelowna/Halifax model", "body": "<p>Victoria's LED streetlight conversion, budgeted at just $150,000, has been delayed by supplier issues. By contrast, <strong>Kelowna</strong> converted 17,000+ lights for $4.9M, achieving <strong>$1M/year in electricity savings alone</strong> and a <strong>400% ROI over 15 years</strong> (<em>Kelowna Now</em>). <strong>Halifax</strong> deployed 44,000 smart LED fixtures with an IoT platform, saving <strong>$5M/year</strong> and creating infrastructure for smart parking, traffic counters, and environmental sensors (<em>Lighting Design & Specification</em>). Victoria has zero smart/connected streetlight capability.</p><p><strong>What we will deploy (and what we will not):</strong></p><p><strong>Yes:</strong></p><ul><li>Full LED conversion of Victoria's ~7,000–10,000 streetlights</li><li>IoT-connected platform for outage detection, brightness modulation, and energy management</li><li>Adaptive dimming (lower intensity during low-use hours, restore quickly on demand)</li><li>Optional add-on environmental sensors (air quality, noise levels) at selected locations</li><li>Better lighting design (warm tones, heritage-compatible fixtures, gap-filling on dark stretches)</li></ul><p><strong>No:</strong></p><ul><li>No audio surveillance (gunshot detection, scream detection, behaviour detection). The available evidence on these systems is mixed at best (the MacArthur Justice Center's analysis of ShotSpotter found weak crime-reduction impact; Chicago dropped the system in 2024). The privacy and Charter implications are serious. The OIPC of BC has cautioned strongly against municipal audio surveillance</li><li>No facial recognition, license-plate reading, or behavioural-pattern AI on streetlights</li><li>No \"directed brightness at suspect\" functionality — lights will brighten on schedule and on need, not in response to AI threat assessment</li></ul><p>The <strong>published evidence base</strong> for street-lighting and crime is real: improved lighting reduces nighttime crime by approximately 21% across systematic-review studies (<em>Welsh & Farrington, Campbell Collaboration</em>). Victoria can capture this benefit — plus the operational savings of Kelowna and Halifax — without crossing into surveillance.</p>", "budget": "$3–5M over 3 years for LED conversion + IoT platform at Victoria's scale. <strong>Self-financing within 3–4 years</strong> through electricity savings (~$500K–1M/year at full deployment) plus avoided maintenance costs from outage detection. Environmental sensor adders at $50K–100K each."},
  {"id": "31", "pillar": "safe", "section": "Strengthen Public Safety", "tier": "core", "title": "Weekly public safety dashboard", "body": "<p>Encampments cleared, response times, sidewalk obstructions addressed, public drug use enforcement actions, referrals to shelter/treatment, needles collected. Published weekly. Accountability you can see.</p><p>No more governing in the dark. If we publish the numbers every week, there is nowhere to hide and no excuse for inaction.</p>", "budget": ""},
  {"id": "32", "pillar": "safe", "section": "Strengthen Public Safety", "tier": "core", "title": "15% crime reduction by 2030", "body": "<p><strong>Continuing the momentum.</strong> Victoria's Crime Severity Index dropped 11% in 2024 to 152.65 — its lowest since 2020 — and property crimes fell to 2013 levels. Real progress that should not be undone. The additional 15% reduction by 2030 builds on this trajectory.</p><p><strong>How we get there:</strong></p><ul><li><strong>Hot-spot policing</strong> at data-identified locations (per Measure 28), with sustained presence shifted as patterns shift</li><li><strong>Visible bike and foot patrols</strong> downtown, Inner Harbour, Beacon Hill Park — Measure 36 specifies these geographies</li><li><strong>Better lighting</strong> (Measure 30, Measure 37, Measure 48) — the systematic-review evidence shows ~21% nighttime crime reduction from improved lighting alone (Welsh & Farrington, Campbell Collaboration)</li><li><strong>Capacity-first enforcement</strong> (Measure 35) means enforcement is consistent and credible, not erratic</li><li><strong>Quarterly community safety surveys</strong> — not just statistics, but resident perception, tracked block-by-block</li></ul><p>This target is aggressive but achievable — cities that combine unified command, better lighting, and data-driven policing consistently achieve 15–25% reductions in comparable indices.</p>", "budget": "Captured within other measures (M26 DPOT, M27 bylaw hours, M30 smart streetlights, M37 lighting). No new spending in this measure itself."},
  {"id": "33", "pillar": "safe", "section": "Restore Order to Public Spaces", "tier": "core", "title": "Enforce existing bylaws consistently", "body": "<p>Victoria already has rules for overnight sheltering in designated parks (down by 7 AM), sidewalk obstruction, and public space use. The problem is enforcement capacity, not missing rules. We don't need new laws — we need to enforce the ones we have.</p>", "budget": ""},
  {"id": "33b", "pillar": "safe", "section": "Restore Order to Public Spaces", "tier": "sub", "title": "Drug-use buffer zones around child-focused spaces", "body": "<p>On the Hammond September 2023 concept (drafted then shelved when the Province pivoted on decriminalization), with the post-May 2024 legal framework now restored: prohibit illicit drug use and possession within 30 metres of expanded \"child-focused spaces\" — defined to include schools, playgrounds, sports fields, tennis courts, picnic tables, bus shelters serving schools, public libraries, and community centres. Enforcement model:</p><ul><li>Verbal direction to move along (first contact)</li><li>Seizure of substances (second contact)</li><li>Referral to outreach and treatment intake, paired with the Phase B capacity work in Measure 35</li><li>Arrest only where required for public safety or persistent non-compliance</li></ul><p>This is not a return to broad criminalization; it is a precisely-scoped buffer rule around the spaces where children gather, consistent with the post-May 7, 2024 BC public-use legal framework.</p>", "budget": "$0 net — enforcement absorbed within DPOT (Measure 26) and extended bylaw hours (Measure 27)."},
  {"id": "34", "pillar": "safe", "section": "Restore Order to Public Spaces", "tier": "core", "title": "Rapid removal protocol for downtown", "body": "<p>Same-day clearing of structures obstructing sidewalks and doorways. Documented process: compliance window (30–60 min) + outreach engagement → if non-compliant, remove, clean, restore. Property stored for retrieval. Humane, consistent, predictable.</p>", "budget": ""},
  {"id": "35", "pillar": "safe", "section": "Restore Order to Public Spaces", "tier": "core", "title": "Capacity-first enforcement", "body": "<p>At 5 PM daily, publish available shelter spaces, suitability flags (women-only, couples, pets, mobility), and intake paths on a public dashboard. When capacity exists and transport is offered, enforce consistently. When it doesn't, focus on daytime removal and sidewalk access.</p><p><strong>The principle:</strong> increase capacity faster than enforcement ramps up. Don't enforce people into nowhere. Partner with BC Housing and nonprofits for managed alternatives outside the core. Modular supportive housing, shelter expansion, converted buildings.</p>", "budget": ""},
  {"id": "36", "pillar": "safe", "section": "Restore Order to Public Spaces", "tier": "core", "title": "Reclaim priority public spaces", "body": "<p>Focus areas for permanent visible presence:</p><ul><li><strong>Inner Harbour and waterfront</strong> — Victoria's front door. Patrols on foot and bicycle, permanent and visible, from 7 AM to midnight</li><li><strong>Centennial Square and Pandora corridor</strong> — the areas where disorder concentrates. Dedicated DPOT presence</li><li><strong>Beacon Hill Park</strong> — families, tourists, seniors must feel safe. Regular mounted or bike patrols</li></ul><p>We will systematically apply the same method to each problem area: massive visible presence → interpellation of offenders → referral of vulnerable individuals to services → sustained presence until order is restored → gradual reduction to maintenance level.</p>", "budget": ""},
  {"id": "37", "pillar": "safe", "section": "Better Lighting for Better Safety", "tier": "core", "title": "Light Victoria properly — all night", "body": "<p>Instead of cutting streetlights at midnight, we will progressively dim intensity while maintaining minimum lighting everywhere, all night. LED technology makes this practical: lower energy consumption, longer lifespan, adjustable intensity on demand.</p><p>We will restore warm, inviting lighting that enhances Victoria's beauty — not cold industrial fixtures but lighting that complements heritage architecture and makes streets feel safe and welcoming after dark.</p><p>Commercial properties will be encouraged to keep storefront and signage lighting on at night — lit storefronts contribute to street safety and neighbourhood vitality.</p>", "budget": "LED conversion is captured under Measure 30. Incremental cost for extended hours: $150K/year in electricity (mitigated by adaptive dimming). Offset by reduced vandalism, reduced crime, and increased nighttime foot traffic supporting businesses."},
  {"id": "38", "pillar": "safe", "section": "Vision Zero: Trending Toward Zero Traffic Deaths", "tier": "core", "title": "Redesign the most dangerous intersections", "body": "<p>Protected left turns, better crosswalk lighting, traffic calming at Blanshard & Hillside, Douglas Street, and other crash hotspots. Study each intersection using GIS-based traffic analysis (Measure 53) and AI consultation imagery (Measure 53b) for community review, then implement the best solution.</p>", "budget": ""},
  {"id": "39", "pillar": "safe", "section": "Vision Zero: Trending Toward Zero Traffic Deaths", "tier": "core", "title": "30 km/h speed limits on residential and downtown streets", "body": "<p>With speed humps, curb bulges, and physical design that makes speeding impractical. Not just signs — physical infrastructure that forces slower driving.</p>", "budget": ""},
  {"id": "40", "pillar": "safe", "section": "Vision Zero: Trending Toward Zero Traffic Deaths", "tier": "core", "title": "Automated speed cameras near every school and playground zone", "body": "<p><strong>Within the BC framework</strong> that authorizes municipal automated speed and red-light enforcement (the Intersection Safety Camera and Automated Speed Enforcement programs administered by the Province and RCMP), Victoria will deploy fixed and mobile speed-camera coverage at:</p><ul><li><strong>Every active school zone</strong> during posted school-zone hours</li><li><strong>Every active playground zone</strong> during playground-zone hours</li><li><strong>Every controlled intersection</strong> with documented multi-year collision history involving pedestrians or cyclists</li></ul><p><strong>Implementation principles:</strong></p><ul><li>Cameras placed at zones based on collision evidence, not as a general revenue tool. The point is speed reduction, not ticket revenue</li><li>All locations publicly mapped and clearly signed</li><li>Ticket revenue applied to additional traffic-safety investments (signal upgrades, pedestrian-crossing improvements, school-area infrastructure) — not to general operating</li><li>Quarterly public reporting on locations, ticket volumes, and measured speed-reduction outcomes</li><li>Coordination with the Province on the regulatory framework and revenue-sharing</li></ul><p>Zero tolerance for speeding where children are present.</p>", "budget": "Largely revenue-neutral to revenue-positive at current ticket-volume assumptions (estimated $300–600K net annual after equipment, processing, and reinvestment in safety infrastructure). Equipment capital: $400K over the term."},
  {"id": "41", "pillar": "safe", "section": "Vision Zero: Trending Toward Zero Traffic Deaths", "tier": "core", "title": "Protected bike lanes on all major routes", "body": "<p><strong>Continuing Victoria's cycling success story.</strong> The 36 km of AAA (All Ages & Abilities) routes built since 2017, with 95% of residents within 500 metres of a safe route, is the strongest cycling infrastructure record of any Canadian city. We will close the remaining gaps and extend the network into the neighbourhoods that still lack it.</p><p><strong>Specifically:</strong></p><ul><li><strong>Protected (physical separation, not painted lines)</strong> on all major commuter and commercial corridors</li><li><strong>Neighbourhood connectors</strong> to close the gaps between the AAA backbone and residential streets that currently force cyclists into mixed traffic</li><li><strong>Improved bike parking</strong> at major destinations (transit hubs, civic facilities, commercial districts), including covered and secure long-term parking</li><li><strong>End-of-trip facilities</strong> required in new major commercial developments — shower, change room, secure bike storage</li><li><strong>Peer-city benchmarking</strong> as the standard for evaluation (Saanich, Esquimalt, Edmonton, Minneapolis, Chicago, Austin, Boston, Nashville, Ann Arbor) — per Coun. Dave Thompson's ongoing peer-city benchmarking work</li><li><strong>Coordination with Measure 25b accessibility</strong> — bike infrastructure must work for adaptive cycles, hand cycles, and the e-bike fleet that older residents and people with disabilities increasingly rely on</li></ul><p>Victoria has the cycling culture; we will keep the infrastructure ahead of the demand.</p>", "budget": "$4–6M over the term for AAA expansion and protected-lane retrofits. The federal Active Transportation Fund and provincial BC Active Transportation Infrastructure Grants typically cover 50–70% on successful application."},
  {"id": "42", "pillar": "safe", "section": "Vision Zero: Trending Toward Zero Traffic Deaths", "tier": "core", "title": "Safety audit for every new road project", "body": "<p>Vision Zero review built into the approval process. No new infrastructure that creates new danger.</p>", "budget": ""},
  {"id": "42b", "pillar": "safe", "section": "Vision Zero: Trending Toward Zero Traffic Deaths", "tier": "sub", "title": "Advocate for federal regulation of vehicle hood height and pedestrian-injury standards", "body": "<p><strong>Extending Coun. Dave Thompson's Vision Zero work</strong> on peer-city benchmarking (Hoboken, Minneapolis, Boston) to the federal regulatory level. Pedestrian fatality rates have risen across North America even as overall vehicle-occupant fatality rates have fallen — a divergence driven substantially by the rising hood height and front-end mass of SUVs and light trucks. This is federal motor vehicle regulatory jurisdiction (Transport Canada, Canada Motor Vehicle Safety Standards). The City does not regulate vehicles, but the City represents the constituency that pays the pedestrian cost.</p><p>Council will pass a formal advocacy resolution to Transport Canada and the Federation of Canadian Municipalities calling for harmonized pedestrian-injury crash standards on the European model (Euro NCAP pedestrian protection, mandatory automated emergency braking on new light trucks and SUVs).</p>", "budget": "$0 (advocacy only)."},
  {"id": "43", "pillar": "beautiful", "section": "The Politics of Beauty", "tier": "core", "title": "Strict design standards in heritage areas", "body": "<p>Complete the update of the Downtown Core Area Plan and Old Town design guidelines. Height and design controls to protect sightlines and human-scale streetscapes. New architecture must complement, not clash.</p><p>Like the great cities of Europe, Victoria's beauty comes from coherent design — a \"design code\" that ensures every new building and renovation fits harmoniously with its context. We will establish clear architectural guidelines: materials, proportions, colours, and massing that respect the character of each neighbourhood. Simple, enforceable rules that make beautiful buildings the path of least resistance.</p>", "budget": ""},
  {"id": "44", "pillar": "beautiful", "section": "The Politics of Beauty", "tier": "core", "title": "Restore Victoria's distinctive street furniture", "body": "<p>Victoria's identity rests partly on its details — lamp posts, benches, planters, bus shelters. Generic replacements erode character. We will:</p><ul><li>Establish a Victoria Heritage Street Furniture Standard — specifying designs that reflect the city's character for all new installations</li><li>As street furniture is replaced through normal lifecycle, require heritage-consistent designs</li><li>Use public-private advertising partnerships to fund bus shelter and kiosk replacements at low net cost to the City</li></ul>", "budget": "Heritage-standard benches, lamp posts, and planters: $300K/year incremental cost above standard replacements. Bus shelters and kiosks: largely offset by advertising revenue under existing models."},
  {"id": "45", "pillar": "beautiful", "section": "The Politics of Beauty", "tier": "core", "title": "Enhance key public spaces", "body": "<p>Centennial Square, Bastion Square, and the waterfront deserve investment. Better lighting, seating, landscaping, and programming (markets, events, performances). These are Victoria's living rooms — they should feel like it.</p>", "budget": ""},
  {"id": "45b", "pillar": "beautiful", "section": "The Politics of Beauty", "tier": "sub", "title": "Pedestrianization pilots — Bastion Square first, Government Street next", "body": "<p>Many of Victoria's most beloved streetscapes were not designed for high-volume car traffic. Successful European and North American cities have moved decisively to give priority to pedestrians and cyclists on signature commercial blocks — typically with measurable lifts in retail sales, foot traffic, and tourism after an initial adjustment period. Victoria has talked about this for years; we will deliver pilots with the rigour and reversibility that makes the experiment honest.</p><ul><li><strong>Bastion Square full pedestrianization</strong> — restore it as the public square it was designed to be, paired with daily programming (markets, performances, public art)</li><li><strong>Government Street (Bastion Square to View Street) seasonal pilot</strong> — weekend pedestrianization from May through September, with controlled vehicle access for deliveries and accessible drop-off. Permanence reconsidered each season based on measured foot-traffic, retail-sales, and resident-feedback data</li><li><strong>Fan Tan Alley pedestrian priority</strong> — preserve the historic character with no vehicle access except emergency</li><li><strong>Digital Twin simulation</strong> — superseded in v1.3 by GIS-based traffic analysis (Measure 53) + AI consultation imagery (Measure 53b) for the visualization step. Model traffic redistribution, delivery flow, accessibility impact, and adjacent-street effects through these tools before any permanent change</li><li><strong>Decision rule:</strong> any pilot that does not meet measurable success criteria at the end of two seasons is reversed; any pilot that meets them is made permanent through normal public process</li></ul><p>Cities consistently report initial business anxiety followed by net retail uplift after 12–24 months. We will pilot honestly — with success criteria published in advance, not after the fact.</p>", "budget": "Pilot operating cost: $200–400K/year (programming, modular bollards, accessibility access, signage). Capital for permanent conversion if confirmed: $1–2M per location. Substantially offset by retail uplift on the pilot blocks (peer cities report 10–20% commercial-activity gains 12–24 months in)."},
  {"id": "46", "pillar": "beautiful", "section": "The Politics of Beauty", "tier": "core", "title": "Protect and restore heritage buildings", "body": "<p>Incentives for adaptive reuse. Tax breaks or grants for owners who restore heritage facades. Zero tolerance for demolition by neglect in Heritage Conservation Areas. Heritage buildings are not obstacles to growth — they are the reason people want to live and visit here.</p>", "budget": "Heritage restoration incentive fund: $500K/year. Leverages private investment at 5–10x ratio."},
  {"id": "46b", "pillar": "beautiful", "section": "The Politics of Beauty", "tier": "sub", "title": "Cultural-venue preservation — protect the venues that make Victoria, Victoria", "body": "<p>The threat of losing Hermann's Jazz Club (continuously operating since 1981) and the broader pressure on independent live-music venues across the downtown core demonstrated that municipal heritage protection cannot rest on building fabric alone — it must also protect <em>use</em>. We will adopt a cultural-venue preservation tool on the precedent of Vancouver's Cultural Spaces program and Toronto's Cultural Hotspot designation:</p><ul><li><strong>Designate</strong> a limited list of cultural venues of city-wide significance (live-music venues, independent theatres, artist studios, long-standing community-arts spaces)</li><li><strong>Right-of-first-refusal</strong> for the City or a designated cultural-spaces non-profit when a designated venue's lease is terminated or property is sold</li><li><strong>Permissive tax exemption</strong> for designated cultural venues that meet programming and accessibility criteria</li><li><strong>Lease-bridge fund</strong> to help designated venues navigate landlord transitions and short-term rent shocks</li></ul><p>Cultural venues are not interchangeable with retail or office uses. Once they close, they almost never come back.</p>", "budget": "Lease-bridge fund: $300K/year. Foregone tax revenue on designated venues: $100–200K/year. Offset by the economic multiplier of preserved cultural anchors (tourism, surrounding-business foot traffic, downtown vitality)."},
  {"id": "47", "pillar": "beautiful", "section": "The Politics of Beauty", "tier": "core", "title": "Expand waterfront walkways", "body": "<p><strong>Continuing Victoria's signature public-realm asset.</strong> Victoria's waterfront is its greatest single public amenity — the Inner Harbour walkway, the David Foster Way, the Songhees and Vic West shoreline routes, and the Ogden Point breakwater are world-class assets that the City has rightly invested in. We will continue connecting and expanding the network so that residents and visitors can walk the entire coastline.</p><p><strong>What we will do:</strong></p><ul><li><strong>Close the gaps</strong> in the existing walkway network — particularly between Songhees and the Selkirk Trestle, and along the Gorge Waterway</li><li><strong>Maintain to a higher standard</strong> — surface, accessibility, lighting, seating, signage, and tactile wayfinding (per Measure 25b)</li><li><strong>Coordinate with the host Nations</strong> (Songhees and Esquimalt) on shoreline access that affects their territorial waters and reserve geographies (per Measure 1)</li><li><strong>Year-round programming</strong> — interpretive signage, public art installations, exercise stations, seasonal events</li><li><strong>Tourism and commercial integration</strong> — the waterfront is also a corridor of restaurants, hotels, and small businesses; the walkway is their front door</li></ul><p>Every metre of walkway added is an investment in tourism, quality of life, and adjacent property values.</p>", "budget": "$1–2M/year capital for gap closures and upgrades. Largely eligible for federal infrastructure and tourism program co-funding."},
  {"id": "48", "pillar": "beautiful", "section": "The Politics of Beauty", "tier": "core", "title": "Extend heritage and ornamental lighting hours", "body": "<p>Victoria's ornamental lighting on heritage buildings and the harbour should not switch off at 10 PM. Maintain heritage lighting until midnight. A city known for beauty should be beautiful after dark.</p>", "budget": "$75K/year in additional electricity costs. LED conversion minimizes this."},
  {"id": "49", "pillar": "beautiful", "section": "The Politics of Beauty", "tier": "core", "title": "Elevate parks and gardens", "body": "<p><strong>Continuing Victoria's identity as a gardens city.</strong> Victoria's parks are world-famous for a reason: Beacon Hill Park, the Inner Harbour gardens, Ross Bay, and Government House grounds are part of the city's identity and a primary tourism draw. The Parks department's mission must include the meticulous, skilled gardening that makes these spaces extraordinary — not \"naturalization\" by default.</p><p><strong>What we will do:</strong></p><ul><li><strong>Restore the Parks operating budget</strong> for skilled horticulture and grounds maintenance to a level that matches the quality of the assets</li><li><strong>Beacon Hill Park as flagship</strong> — a comprehensive 5-year restoration plan covering pathways, plantings, water features, the Children's Farm, signage, and seating</li><li><strong>Inner Harbour gardens as Victoria's front door</strong> — best-practice horticulture, year-round colour, and night lighting (per Measure 48)</li><li><strong>Neighbourhood parks</strong> — every neighbourhood gets at least one signature horticultural feature, programmed and maintained</li><li><strong>Free seedling program for homeowners</strong> — 75% of Victoria's urban forest is on private land; we partner with residents on canopy growth (per Measure 61)</li><li><strong>Royal Athletic Park and sport-oriented parks</strong> (per Measure 52) are treated as part of the same network, not as a separate category</li></ul><p>Intentional beauty, not afterthought.</p>", "budget": "$400–600K/year operating uplift over current Parks budget. Significant offset through tourism revenue (Victoria's gardens are a top citable tourist draw in Condé Nast surveys)."},
  {"id": "50", "pillar": "beautiful", "section": "Liberate Cultural, Festive, and Sporting Life", "tier": "core", "title": "Extended hours for civic cultural spaces", "body": "<p>The Royal BC Museum is provincial, but Victoria's civic cultural spaces (Crystal Garden, McPherson Theatre programming, public libraries) should offer extended evening and weekend hours. Culture should be accessible to people who work during the day. Two evenings per week open until 9 PM. Sunday hours for libraries.</p>", "budget": "$200K/year for extended staff hours (overtime, no new hires)."},
  {"id": "51", "pillar": "beautiful", "section": "Liberate Cultural, Festive, and Sporting Life", "tier": "core", "title": "Activate outdoor spaces for year-round use", "body": "<p><strong>Victoria's mild climate is a competitive advantage</strong> that the City under-uses. We will:</p><ul><li><strong>Heated outdoor patios</strong> for restaurants (electric / heat-pump, non-polluting) — streamlined permitting and a published design standard</li><li><strong>Expanded night markets</strong> in public squares — weekly during the summer, monthly during the shoulder seasons, with simplified vendor licensing</li><li><strong>Pop-up events and seasonal programming</strong> in Centennial Square, Bastion Square, the Inner Harbour walkway, and Beacon Hill Park</li><li><strong>Busking and street performance</strong> — designated zones, simple licensing, no harassment of legitimate performers (current City rules are inconsistently applied)</li><li><strong>Active-use design</strong> for new public spaces — benches that work for everyone, lighting that invites evening use, accessible WCs (per Measure 24b), and Wi-Fi (per Measure 56)</li><li><strong>Year-round Christmas / festival market</strong> at the Inner Harbour and Government Street — a permanent fixture that draws tourism and supports adjacent commerce</li></ul><p>The cities that win in the post-pandemic era are the ones that make their public spaces work. Victoria has the bones; we will activate them.</p>", "budget": "$300–500K/year for programming, permitting capacity, and operating costs. Substantially offset by event-related business-tax uplift and tourism revenue."},
  {"id": "52", "pillar": "beautiful", "section": "Liberate Cultural, Festive, and Sporting Life", "tier": "core", "title": "Sport facilities — use them fully, including Royal Athletic Park", "body": "<p>Victoria's recreational facilities are often underused during off-peak hours. We will partner with employers to offer corporate access during these windows, generating revenue and promoting employee health. Facilities should be open from 6 AM to 10 PM, with expanded weekend programming.</p><p><strong>Continuing the Royal Athletic Park commitment.</strong> Mayor Alto's 2022 platform included Royal Athletic Park enhancements as a stated priority. The 2025 CSWB Phase 1 funding pulled <strong>$1.5M from Royal Athletic Park upgrades</strong> to fund downtown-safety operations — a tradeoff that should not have been necessary, and one residents did not vote for. We will:</p><ul><li><strong>Restore the Royal Athletic Park enhancement budget</strong> reallocated in 2025, over the next two budget cycles</li><li><strong>Complete the deferred facility upgrades</strong> — seating, surface, lighting, accessibility</li><li><strong>Expand programming</strong> with the Victoria HarbourCats, School District 61 partners, and community sport organizations</li><li><strong>Position Royal Athletic Park</strong> as a regional sport-events draw, not just a local facility — events generate visitor spending that flows directly to surrounding businesses</li></ul>", "budget": "$1.5M restoration over two budget cycles to recover reallocated funds; $300K/year operating uplift for expanded programming. Partially offset by user-fee revenue from corporate, school-district, and event use."},
  {"id": "53", "pillar": "beautiful", "section": "Victoria as a Technology Leader", "tier": "core", "title": "Modernize Victoria's GIS (Geographic Information System) and underground utility data", "body": "<p><strong>Currently:</strong> Victoria's underground utility records — water, stormwater, sanitary sewer, telecom conduit — are partially digitized, inconsistently updated across departments, and not always coordinated with permit-issuing or capital-planning staff. The result: re-trenched streets, surprise utility hits during construction, repeated excavation of the same blocks within years, and significant un-budgeted repair costs. The City does not currently publish utility-coordination performance metrics.</p><p><strong>ACTW:</strong> A focused modernization of the City's geospatial data and utility records — the practical, evidence-grounded foundation any later visualization or digital-twin work would require, but a worthwhile investment on its own terms.</p><p><strong>What we will do:</strong></p><ul><li><strong>Comprehensive utility records audit and migration</strong> to a unified GIS platform — water, stormwater, sanitary sewer, telecom conduit</li><li><strong>Inter-departmental coordination protocol</strong> — every capital project, every utility work order, every permit applies against the same map. No more parallel records</li><li><strong>Permit-system integration</strong> so applicants and staff see the full subsurface picture at point of decision</li><li><strong>Construction coordination dashboard</strong> — quarterly publication of all planned excavation work to reduce re-trenching</li><li><strong>Open standards and Canadian data sovereignty</strong> — no vendor lock-in, data stored on Canadian servers, exportable in open formats</li><li><strong>Co-funding pursued</strong> through federal Infrastructure Canada modernization programs and provincial Local Government Modernization Grants</li></ul><p><strong>Why this and not a full Digital Twin (v1.3 honest reframe):</strong></p><p>The Helsinki, Singapore, and Boston digital-twin deployments cited in earlier versions of this framework served cities 7–25× Victoria's population, with project-density and grant-funding profiles Victoria does not share. No Canadian municipality of Victoria's scale (~92K residents) has successfully deployed and sustained a full city-scale digital twin. The honest assessment: the underground-utility-coordination case is real and Victoria-sized; the full-city digital-simulation case is not, at this stage. We modernize the data first. The simulation tools become viable later if and only if the data and the use case justify them — see the future-state note at the end of this section.</p>", "budget": "$400–800K capital one-time, ~$50–80K/year ongoing for data maintenance and platform licensing. Substantial co-funding eligible (50–70% typical for federal/provincial municipal-modernization grants). Direct ROI: reduced re-trenching costs (industry estimates: 15–25% reduction in utility-conflict repair costs); faster permit decisions; fewer construction surprises."},
  {"id": "53b", "pillar": "beautiful", "section": "Victoria as a Technology Leader", "tier": "sub", "title": "AI-generated public consultation imagery", "body": "<p><strong>Continuing Coun. Matt Dell's precedent</strong> from the Beacon Hill All-Weather Field reimagining (<em>CHEK News</em>, 2025). The City uses mature, low-cost AI image-generation tools to produce realistic visualizations of proposed projects for public consultation — at a fraction of the cost of conventional architectural renderings, small enough to deploy on every meaningful public-consultation project.</p><p><strong>Implementation:</strong></p><ul><li>Project teams generate 3–5 visualization options per major project for public comment</li><li>Visualizations clearly labelled as <strong>AI-generated illustrations</strong>, not engineering drawings</li><li>Always accompanied by underlying plans, dimensions, and impact data — illustrations supplement, not replace, the technical record</li><li>Cost is a fraction of conventional architectural renderings (typically $1–3K per visualization vs. $15–40K for full renderings)</li><li>Output published in the public-consultation portal (Measure 79) for every project triggering the 5-step process (Measure 78)</li></ul><p><strong>v1.3 reframe:</strong> This is now a <strong>permanent measure on its own merits</strong>, not a \"bridge\" to a Digital Twin. It captures the bulk of citizen-facing visual-impact value at a small fraction of the cost of a full simulation tool.</p>", "budget": "$30–50K/year operating across all public consultations. Within existing public-consultation budget envelope."},
  {"id": "53c", "pillar": "beautiful", "section": "Victoria as a Technology Leader", "tier": "sub", "title": "One-time LIDAR scan of downtown core", "body": "<p><strong>A one-time aerial and street-level LIDAR survey</strong> of the downtown core (Inner Harbour to Quadra, View to Yates) — approximately 2 km². LIDAR (Light Detection And Ranging) produces a high-resolution 3D point cloud of buildings, streetscapes, vegetation, and infrastructure.</p><p><strong>Why this matters as a standalone investment:</strong></p><ul><li><strong>Heritage protection:</strong> every heritage building digitally archived at high resolution — invaluable for restoration, fire-loss insurance documentation, and conservation planning</li><li><strong>Emergency management:</strong> post-disaster recovery planning has a baseline 3D record of pre-disaster downtown</li><li><strong>Planning and development:</strong> developers, architects, and the City share a single accurate baseline for proposed builds and impact analysis</li><li><strong>Public consultation:</strong> LIDAR-derived 3D models feed directly into M53b AI consultation imagery</li><li><strong>Future-state option:</strong> if a full digital-twin investment ever makes sense, LIDAR is the foundational data layer it would require — but the scan is worth doing on its own merits regardless</li></ul><p><strong>Vendor neutrality:</strong> open data formats (LAS / LAZ), published to the open data portal (Measure 56), available to local technology companies, academic researchers, and the public.</p>", "budget": "$150–250K one-time capital. Co-funding eligible through federal Heritage Canada programs and provincial Disaster Mitigation Funds. No recurring cost (scan refreshed approximately every 10 years)."},
  {"id": "54", "pillar": "beautiful", "section": "Victoria as a Technology Leader", "tier": "core", "title": "Adaptive traffic signal control (Measure 19)", "body": "<p>Covered in detail under Mobility. Adaptive signals and the modernized GIS (Measure 53) are complementary: shared geospatial data supports traffic-pattern analysis, signal-timing decisions, and integrated construction coordination.</p>", "budget": ""},
  {"id": "55", "pillar": "beautiful", "section": "Victoria as a Technology Leader", "tier": "core", "title": "Favour local technology companies in city procurement", "body": "<p><strong>Victoria has one of the strongest concentrations of technology talent per capita in Canada</strong> — the cluster around the Atrium, Fort Tectoria, Vancouver Island Technology Park, and UVic spin-offs is a real economic asset that the City has not systematically leveraged.</p><p><strong>What we will do:</strong></p><ul><li><strong>Local-preference scoring</strong> in procurement for tools and services available locally — permit systems, traffic management, data platforms, civic-engagement software, accessibility tech</li><li><strong>Plain-language RFP requirements</strong> that do not favour large incumbent vendors over local startups</li><li><strong>Innovation pilot framework</strong> — small contracts ($25K–$100K) for local companies to pilot solutions to specific civic problems, with a clear path to scale-up</li><li><strong>Open data and APIs</strong> (per Measure 56) — Victoria's data should be available to local developers and entrepreneurs to build products</li><li><strong>Data sovereignty</strong> — City data stored on Canadian servers, subject to Canadian privacy law (BC FOIPPA and federal PIPEDA). No US-cloud lock-in for sensitive municipal data</li></ul><p>The best way to support a local industry is not subsidies — it is contracts. Real work, real revenue, real accountability.</p>", "budget": "Revenue-neutral. The procurement budget already exists; we are changing scoring and accessibility, not adding spending."},
  {"id": "56", "pillar": "beautiful", "section": "Victoria as a Technology Leader", "tier": "core", "title": "Open data portal and environmental sensors", "body": "<p>Expand Victoria's open data portal with real-time transit data, traffic counts, air quality readings, and parking availability. Support community-driven solutions — transit apps, bike route planners, air quality alerts — by making city data freely available in machine-readable formats.</p><p>Deploy air quality sensors in key locations (downtown, near schools, waterfront) to provide real-time readings during wildfire smoke season. This costs very little and provides enormous value to residents making daily health decisions.</p><p>Free public Wi-Fi in Centennial Square, the Inner Harbour, and all City facilities.</p>", "budget": "Open data portal expansion: $75K one-time. Air quality sensors (10 units): $50K setup, $15K/year maintenance. Public Wi-Fi expansion: $100K setup, $30K/year. Total: $225K setup, $45K/year ongoing."},
  {"id": "57", "pillar": "beautiful", "section": "Victoria as a Technology Leader", "tier": "core", "title": "Support EV charging infrastructure", "body": "<p>Work with BC Hydro and private operators to expand public EV charging across Victoria — at City parkades, community centres, and new developments. Require EV-ready wiring in all new residential and commercial construction (already supported by BC Building Code). This is not ideology — it is infrastructure for the vehicles that are already being sold.</p>", "budget": "$0 direct City cost for private-operator installations. Requirement for new construction: already in provincial code. City parkade charger installations: $200K over the term (recoverable through usage fees)."},
  {"id": "58", "pillar": "beautiful", "section": "Climate Resilience — Practical, Not Ideological", "tier": "core", "title": "Reaffirm and pursue Victoria's climate targets", "body": "<p><strong>Continuing Victoria's Climate Leadership Plan.</strong> The 2019 climate emergency declaration and the subsequent Climate Leadership Plan set the right targets; the gap is delivery and reporting. We will continue the framework and close the delivery gap.</p><ul><li><strong>50% community GHG reduction by 2030</strong> (vs. 2007 levels) — requiring 19 more percentage points from the 31% already achieved</li><li>100% renewable energy by 2050</li><li>Carbon-neutral by mid-century</li></ul><p>The City alone cannot achieve these — provincial and federal action is essential. But Victoria can lead by example and move faster than the minimum. We will track and <strong>publish progress annually</strong>, including actual uptake numbers for the Climate Friendly Homes program, which the current council has <strong>not published</strong>.</p>", "budget": ""},
  {"id": "59", "pillar": "beautiful", "section": "Climate Resilience — Practical, Not Ideological", "tier": "core", "title": "Upgrade aging stormwater infrastructure", "body": "<p>Replace the oldest systems first. Incorporate green infrastructure: permeable surfaces, rain gardens, urban wetlands. Prepare coastal areas for sea-level rise. Victoria's stormwater system includes pipes over 100 years old — these are ticking time bombs during heavy rain events.</p>", "budget": "$5–8M/year in capital spending (partially budgeted). Green infrastructure components reduce long-term maintenance costs. Seek federal/provincial infrastructure grants to offset."},
  {"id": "60", "pillar": "beautiful", "section": "Climate Resilience — Practical, Not Ideological", "tier": "core", "title": "Expand Climate Friendly Homes program", "body": "<p><strong>Continuing and expanding a program that works.</strong> The Climate Friendly Homes retrofit program is one of the current administration's strongest climate plays — the principal weakness is that the City has not published uptake numbers, so neither the program nor its critics can judge how well it is working. We will continue and expand it, with full transparency.</p><ul><li><strong>More rebates</strong> for insulation, heat pumps, and solar panels</li><li><strong>Help homeowners cut emissions and energy bills</strong> simultaneously</li><li><strong>Create green economy jobs</strong> in retrofitting and clean tech</li><li><strong>Publish annual uptake numbers</strong> (homes served, retrofit type, dollars deployed, estimated GHG reduction) on the quarterly performance dashboard (Measure 67)</li></ul><p>A homeowner who saves $200/month on energy bills does not need ideology to support climate action — they need a good program and a clear application process.</p>", "budget": ""},
  {"id": "61", "pillar": "beautiful", "section": "Climate Resilience — Practical, Not Ideological", "tier": "core", "title": "Plant 5,000 new trees by 2030", "body": "<p><strong>Continuing and expanding Mayor Alto's 2022 parks-acquisition and urban-forest commitments.</strong> Climate-resilient species on streets, in parks, and through community programs. Increase urban canopy from 28% toward 30%+. Shade, carbon sequestration, stormwater management, and beauty — all from one investment.</p><p>Continue and expand the partnership with community groups and schools for neighbourhood planting events. Offer free seedlings to homeowners — 75% of Victoria's urban forest is on private land, so the canopy goal cannot be met by City-owned streets alone. Coordinate with the Songhees and Esquimalt Nations on tree planting in culturally-significant areas (per Measure 1).</p>", "budget": ""},
  {"id": "62", "pillar": "beautiful", "section": "Climate Resilience — Practical, Not Ideological", "tier": "core", "title": "60% of trips by transit, walking, or cycling by 2030", "body": "<p>Accelerating the Official Community Plan's 2041 target by 11 years. Less congestion, lower emissions, better health, livelier streets. See Mobility measures for how we get there.</p>", "budget": ""},
  {"id": "63", "pillar": "beautiful", "section": "Climate Resilience — Practical, Not Ideological", "tier": "core", "title": "Protect ecosystems and biodiversity", "body": "<p>Maintain 2.7+ hectares of parkland per 1,000 residents as population grows. Protect Garry Oak ecosystems and rare habitats. Restore shoreline habitats. Maintain 36% of parkland in natural state for biodiversity. Green space preservation doubles as climate action.</p>", "budget": ""},
  {"id": "64", "pillar": "beautiful", "section": "Climate Resilience — Practical, Not Ideological", "tier": "core", "title": "Emergency preparedness for extreme weather — including a maximum-temperature rental bylaw", "body": "<p>Heatwave cooling centres in every neighbourhood, air quality advisory protocols for wildfire smoke, flood response plans for coastal and low-lying areas. Protect vulnerable residents first — seniors, people with respiratory conditions, people without air conditioning.</p><p><strong>Maximum-temperature rental bylaw.</strong> The 2021 BC heat dome killed 619 people, most of them indoors, most of them in rental units with no functional cooling. Following the precedent of New Westminster (adopted April 2026) and the Dell/Caradonna/Thompson motion now before Victoria council (May 2026), we will adopt a maximum-temperature rental bylaw requiring landlords to maintain at least one room of every rental unit at no more than 26°C during declared heat-warning periods. Implementation:</p><ul><li>Tied to the BC Building Code and the Standards of Maintenance Bylaw, not as a new standalone instrument</li><li>Reasonable transition window (24–36 months) for existing stock</li><li>Compliance via portable cooling, heat pumps, or built-in mechanical cooling — landlord's choice</li><li>Council will also formally advocate to the Province for enabling legislation that overrides strata bylaws that currently prohibit window or portable AC units, where unit-specific health needs require them</li></ul>", "budget": "Emergency preparedness enhancements: $300K/year. Cooling centre operations during heat events: $100K/year. Bylaw enforcement during heat events: $150K/year incremental, mostly through Phase A DPOT mobilization. Small costs that save lives."},
  {"id": "65", "pillar": "managed", "section": "Spend Less, Deliver More", "tier": "core", "title": "Zero-based budgeting review of all 200+ city programs", "body": "<p>Every program must justify its existence from scratch. Not \"last year's budget plus 3%\" — every dollar must be re-earned.</p><p>We will examine every line item the way an entrepreneur examines expenses: Does this program deliver measurable results? What is the cost per beneficiary? Is there a more efficient way to achieve the same outcome? If a program cannot demonstrate its value, it gets cut or restructured.</p><p><strong>Specific targets:</strong></p><ul><li>Review all grants and subsidies over $50,000/year. Criteria: actual utilization, cost per beneficiary, alignment with core municipal priorities, self-funding ratio. Any grant whose cost per beneficiary is disproportionate will be reduced or eliminated</li><li>Identify and eliminate symbolic programs that produce reports, strategies, and consultations but no measurable change in residents' lives</li></ul><p><strong>Peer city precedent:</strong> Calgary's <strong>SAVE program</strong> (rotating Zero-Based Reviews, 2012–2019) <strong>targeted $74 million in operational savings by 2022</strong> (<em>City of Calgary newsroom, February 2020</em>). At Calgary Council on March 31, 2026, KPMG's Chris Sainsbury reported that SAVE <strong>had found $60 million in operational cash to that date</strong> (<em>LiveWire Calgary, March 31, 2026</em>). Greater Sudbury's Auditor General recommended incorporating ZBB techniques into value-for-money audits as a pragmatic compromise (<em>Greater Sudbury AG Report, 2023</em>). No comparable Canadian city uses formal ZBB at this scale — Victoria would be a pioneer in BC. Applied to Victoria's $384M operating budget, even modest 2–3% savings per reviewed area could yield $2–3M annually. We will review 3–4 service areas per budget cycle on a rotating basis.</p>", "budget": "Target: $3–6M/year in savings from eliminated or restructured programs by end of term (a conservative fraction of Calgary's documented operational cash recovery)."},
  {"id": "66", "pillar": "managed", "section": "Spend Less, Deliver More", "tier": "core", "title": "Moderate and predictable tax increases — a glide path", "body": "<p>Tie property tax increases to a published formula: <strong>CPI + population growth + a documented efficiency-gain adjustment, with a target of inflation + growth (≈3.5%) once the savings measures in this framework are fully realized.</strong></p><p><strong>Honest staging:</strong></p><ul><li><strong>Year 1:</strong> Tax increase capped at 6.5% (versus the council's 10.44% draft) — partial implementation of efficiency measures</li><li><strong>Year 2:</strong> Tax increase capped at 5%</li><li><strong>Year 3+:</strong> Tax increase capped at CPI + population growth (≈3.5%) once managed competition, ZBB, and administrative attrition savings are realized</li><li>Any increase above the published cap requires a supermajority of Council (6 of 8) and a public explanation</li></ul><p>This is the honest answer. We do not promise day-one delivery of full savings; we promise a credible glide path with quarterly reporting on whether the savings are tracking.</p>", "budget": ""},
  {"id": "67", "pillar": "managed", "section": "Spend Less, Deliver More", "tier": "core", "title": "Quarterly performance dashboard", "body": "<p><strong>Currently:</strong> Victoria publishes no quarterly KPI dashboard. Salary and benefits as a share of operating budget are not reported in an accessible format. Total municipal debt outstanding and debt-to-revenue ratios are buried in technical financial plans. The result: voters cannot hold elected officials accountable between elections.</p><p><strong>ACTW:</strong> Permit timelines, pothole repair times, 311 response rates, crime statistics, housing approvals, budget variance, debt service, salary share of operating budget, Climate Friendly Homes uptake, and the 12 commitments scorecard. <strong>Published online every quarter. Explained in plain language. No hiding.</strong></p><p>This is the core of democratic accountability. If you can see the numbers every quarter, you can hold elected officials accountable every quarter. Not once every four years at election time, but continuously. Coun. Marg Gardiner's existing monthly fiscal newsletter is the closest current-council precedent — ACTW formalizes the practice as a city-wide service standard.</p>", "budget": ""},
  {"id": "68", "pillar": "managed", "section": "Spend Less, Deliver More", "tier": "core", "title": "Reduce administrative overhead through technology and attrition", "body": "<p>Streamline internal processes before asking taxpayers for more. Every form a resident fills out, every process that requires visiting City Hall in person, every paper-based workflow — digitize it.</p><p><strong>Non-replacement of departing administrative staff:</strong> As staff retire, resign, or move on, we will not automatically replace every position. Each vacancy will be assessed: can technology handle this? Can the work be redistributed? Is the position still necessary given digital tools?</p><p>Target: reduce administrative FTEs by 10% over the term through attrition alone. <strong>No layoffs.</strong> Natural departures only.</p>", "budget": "10% reduction in administrative overhead through attrition: $2–3M/year by end of term. Technology investments: $500K/year. Net savings: $1.5–2.5M/year."},
  {"id": "69", "pillar": "managed", "section": "Spend Less, Deliver More", "tier": "core", "title": "Rationalize the City's real estate holdings", "body": "<p>Conduct a full inventory and utilization audit of all city-owned properties. Sell or lease properties that do not serve essential public functions. Use proceeds to reduce debt and fund priority capital projects. When selling, require buyers to meet community benefit criteria (housing, employment, public access) where appropriate.</p>", "budget": "Depends on findings of the audit. Conservative estimate: $5–10M in one-time proceeds from sales over the term."},
  {"id": "70", "pillar": "managed", "section": "Spend Less, Deliver More", "tier": "core", "title": "Seek provincial and federal partnerships for capital projects", "body": "<p>The City shouldn't build alone what senior governments should co-fund. Active advocacy for infrastructure dollars. Maintain low debt ratios. Every federal or provincial dollar attracted is a dollar not taken from property taxes.</p>", "budget": ""},
  {"id": "70b", "pillar": "managed", "section": "Spend Less, Deliver More", "tier": "sub", "title": "Confront provincial downloading — public ledger, formal advocacy, and a published refusal threshold", "body": "<p>Successive provincial governments — across parties — have offloaded responsibilities onto municipalities (mental health, addictions, social housing operations, decriminalization compliance, encampment management) without commensurate funding transfer. Council members across the political spectrum have flagged this: Mayor Alto (downloading as a driver of the 2026 tax hike), Coun. Hammond (the structural mismatch between local revenue tools and downloaded mandates), Coun. Kim (the broken municipal taxation framework itself). It is one of the few points of cross-bloc agreement on council.</p><p>We will operationalize that agreement:</p><ul><li><strong>Quarterly downloading ledger</strong> — a published list of every provincial or federal mandate that the City delivers without dedicated funding, with estimated annual cost per file</li><li><strong>Formal advocacy resolutions</strong> twice per year to UBCM and FCM, calling for either funding transfer or mandate return — file by file, not generic motions</li><li><strong>Published refusal threshold</strong> — services the City will not assume additional responsibility for without dedicated, indexed funding. Examples: net new supportive-housing operations, net new addictions services. The point is not to abandon vulnerable residents — it is to refuse to be the funding pressure-valve for senior-government underinvestment</li><li><strong>Coordinate with Esquimalt, Saanich, Oak Bay</strong> through CRD to present a unified regional position</li></ul>", "budget": "$0 direct cost. Indirect benefit is that every successful funding transfer or mandate return is direct property-tax relief, on the order of hundreds of thousands to millions per file."},
  {"id": "71", "pillar": "managed", "section": "Grow the Tax Base, Don't Just Tax More", "tier": "core", "title": "Cut downtown storefront vacancy from 11% to 5%", "body": "<p>Economic development initiatives, tax incentives for occupying vacant spaces, streamlined tenant improvement permits, animated downtown programming (night markets, pop-ups, public events).</p><p><em>This measure addresses commercial storefront vacancy. The related but separate problem of residential short-term rental conversion is handled under Measure 9b.</em></p><p><strong>On vacant-storefront taxation:</strong> Imposing a property tax surcharge on long-vacant commercial properties typically requires <strong>provincial enabling legislation</strong> — Vancouver's Empty Homes Tax sits within a specific provincial framework (Vacancy Tax / Speculation and Vacancy Tax). The City will:</p><ul><li><strong>Advocate to the Province</strong> for enabling legislation that would allow municipalities to surcharge persistent commercial vacancies, on the BC residential model</li><li><strong>Use existing municipal levers immediately:</strong> vacant property licensing requirements, façade-improvement-or-lease conditions on business licence renewals, pop-up tenancy facilitation programs, and targeted business attraction grants for filling priority storefronts</li><li><strong>Publish a quarterly downtown vacancy report</strong> by block and by sector — transparency itself creates pressure on owners to lease at market rates</li></ul>", "budget": "Business attraction and pop-up facilitation: $300K/year. New business tax revenue from occupied spaces: $500K–1M/year. Plus the economic multiplier of dozens of new businesses and hundreds of jobs."},
  {"id": "72", "pillar": "managed", "section": "Grow the Tax Base, Don't Just Tax More", "tier": "core", "title": "Support small business — reduce red tape, treat operators with respect", "body": "<p><strong>The problem:</strong> Small businesses create the majority of Victoria's private-sector jobs, but they are the businesses least able to absorb regulatory friction — permit delays, complex licensing, inconsistent enforcement, and a slow City Hall that does not value their time.</p><p><strong>What we will do:</strong></p><ul><li><strong>Business licence processing: 5 business days, maximum.</strong> Not 5 weeks. Most licences are renewals or low-risk new applications that need a documented turnaround</li><li><strong>Tenant-improvement permits</strong> for commercial fit-outs: published 6-week target (aligned with Measure 7 simple-permit benchmark)</li><li><strong>Designated downtown economic coordinator</strong> — single point of contact for storefront operators, with authority to escalate stalled files</li><li><strong>Proactive recruitment for vacant storefronts</strong> (per Measure 71) — the City should be calling promising retailers and helping them open</li><li><strong>\"Welcome / thank you\" small-business program</strong> — continuing the Alto 2022 plank, never delivered. A brief in-person visit from a Council member or senior staff to new and long-tenured businesses, with a focused conversation about what the City can fix</li><li><strong>Tax relief for community-serving non-profits and small businesses</strong> — continuing the Alto 2022 plank under section 224 of the Community Charter. Published criteria, transparent decisions, no political favouritism</li></ul><p>Treat small business operators the way the City treats its largest taxpayers — as customers, not applicants.</p>", "budget": "$200K/year for the downtown economic coordinator and outreach program. Largely offset by faster licence revenue, new business openings, and reduced storefront vacancy (Measure 71)."},
  {"id": "73", "pillar": "managed", "section": "Grow the Tax Base, Don't Just Tax More", "tier": "core", "title": "Promote tourism recovery", "body": "<p><strong>Continuing the post-pandemic momentum.</strong> Victoria's tourism numbers are back: ferry traffic up 2%, cruise ships increasing, hotel occupancy near pre-pandemic levels, Condé Nast Traveller \"best small city\" for the third time in 2025. Tourism employs roughly 22,000 people across the Capital Region and underwrites a substantial share of Victoria's small-business ecosystem.</p><p><strong>What we will do:</strong></p><ul><li><strong>Better wayfinding</strong> — Victoria's directional signage is inconsistent and dated; visitors get lost between obvious destinations. A unified wayfinding system tied to the Heritage Street Furniture Standard (Measure 44)</li><li><strong>Extended business hours</strong> in commercial areas — too many Victoria businesses close at 5 or 6 PM in summer, when foot traffic is peaking</li><li><strong>Waterfront activation</strong> (Measure 47) and outdoor programming (Measure 51) as tourism infrastructure</li><li><strong>Cruise-ship coordination</strong> with the Greater Victoria Harbour Authority on visitor flow, with downtown businesses on logistics, and on Pier 21 / James Bay neighbourhood impact</li><li><strong>Marketing partnership</strong> with Destination Greater Victoria — Victoria should be marketed nationally and internationally as Canada's most liveable small city, because it is, or will be</li><li><strong>Indigenous tourism partnership</strong> with the Songhees and Esquimalt Nations (per Measure 1) on shared cultural-tourism products that direct revenue to the Nations</li></ul><p>Tourism is not separate from the rest of the city — a clean, safe, beautiful, well-managed Victoria is the best tourism strategy that exists.</p>", "budget": "$300K/year incremental marketing partnership and wayfinding maintenance. Substantially offset by visitor spending (estimated $1.5B+/year regionally pre-pandemic, recovering)."},
  {"id": "74", "pillar": "managed", "section": "Grow the Tax Base, Don't Just Tax More", "tier": "core", "title": "Major new capital projects require voter approval", "body": "<p>Following the Crystal Pool referendum model and within the BC Local Government Act / Community Charter framework. <strong>Any new (non-lifecycle) capital project exceeding $25 million</strong> goes to the public via Assent Voting or the Alternative Approval Process, as the statutory framework permits.</p><p><strong>The Crystal Pool replacement continues as voted.</strong> In February 2025, 58.7% of Victoria voters approved $168.9M in borrowing for the Crystal Pool replacement under a referendum process. That decision stands. Lifecycle replacement of existing infrastructure proceeds; the Crystal Pool referendum is the exact precedent ACTW Measure 77 and Measure 78 are designed to make standard practice.</p><p><strong>What is included in the $25M threshold:</strong> new community centres, new arenas, new pools (the Crystal Pool replacement was already approved through this mechanism), new civic buildings, major new park developments, significant scope-changing renovations.</p><p><strong>What is not included:</strong> lifecycle replacement of existing infrastructure (stormwater pipes, road resurfacing, water/sewer renewal, bridge rehabilitation, statutory infrastructure obligations). Lifecycle work is the City's basic statutory and operational duty; subjecting it to referendum would block essential maintenance.</p><p>When the City spends big on <strong>new</strong> capital, residents decide. Not consultants. Not councillors alone. You.</p>", "budget": ""},
  {"id": "75", "pillar": "managed", "section": "Lower the Cost of Living — Specific Measures", "tier": "core", "title": "First-hour free parking", "body": "<p>See Measure 24. Direct savings for every resident who drives downtown.</p>", "budget": ""},
  {"id": "76", "pillar": "managed", "section": "Lower the Cost of Living — Specific Measures", "tier": "core", "title": "Reduce permit fees for homeowners doing small renovations", "body": "<p><strong>The problem:</strong> Garden suites, accessibility modifications, energy retrofits, and small additions get caught in the same fee structure as multi-unit developments. The result: homeowners are deterred from doing the work, or do it without a permit — neither of which serves the City.</p><p><strong>What we will do:</strong></p><ul><li><strong>Reduced or waived fees</strong> for projects under $50K that:</li><li>Add housing (secondary suite, garden suite, lock-off unit, in-law suite)</li><li>Improve accessibility (per Measure 25b — ramps, grab bars, accessible bathrooms, widened doors)</li><li>Improve energy efficiency (insulation, heat pumps, solar, electrical upgrades for EV charging)</li><li>Restore heritage features</li><li><strong>Published one-day-turnaround target</strong> for these simple categories (per Measure 7 simple-permit benchmark)</li><li><strong>Pre-approved design library</strong> — common garden-suite, secondary-suite, and accessibility-retrofit designs pre-screened for compliance, available to homeowners free of charge</li><li><strong>Online permit application</strong> for these categories (per Measure 7) — no need to come to City Hall</li></ul><p>Faster, cheaper, easier permits for the projects we actually want more of.</p>", "budget": "$100–150K/year in foregone permit-fee revenue. Substantially offset by faster property-value uplift (and corresponding property-tax base growth) plus reduced under-permitting (which costs more to clean up after)."},
  {"id": "77", "pillar": "democratic", "section": "Direct Democracy and Transparency", "tier": "core", "title": "Referendums for new capital projects over $25 million", "body": "<p>Not just consultations where input gets filed away. <strong>Binding votes</strong>, within the BC Local Government Act and Community Charter framework (Assent Voting or Alternative Approval Process).</p><p>The Dowler Place controversy proved why this matters. A CHEK News FOI revealed the mayor's confidential draft plan to relocate the Pandora encampment was far broader than publicly disclosed. Mayor Alto admitted council skipped community engagement because \"we knew what the comments would be\" (<em>CHEK News</em>). She later apologized (<em>Capital Daily</em>), but the episode — combined with firefighter Josh Montgomery's one-day suspension for criticizing the plan, which prompted Premier Eby to demand an apology and a <a href=\"http://Change.org\" target=\"_blank\" rel=\"noopener\">Change.org</a> petition calling for Alto's resignation — cemented a perception of closed-door governance.</p><p>This cannot happen again. Referendums for new capital, the 5-step process, and the quarterly dashboards are the antidote.</p>", "budget": ""},
  {"id": "78", "pillar": "democratic", "section": "Direct Democracy and Transparency", "tier": "core", "title": "The 5-step process for every major public project", "body": "<p><strong>Currently:</strong> The Dowler Place file is the cleanest illustration of what happens without a required process. Mayor Alto's confidential draft motion to relocate the Pandora encampment was disclosed via CHEK News FOI in June 2025; the mayor stated publicly that early consultation was skipped because <em>\"we knew what the comments would be from the public.\"</em> She apologized for a \"rocky\" rollout, but the underlying problem was structural — there was no required process to follow, so the process was skipped.</p><p><strong>ACTW: every major public project goes through five steps, in this order, no exceptions:</strong></p><p>1. <strong>Local consultation</strong> — problems, pain points, what needs to improve</p><p>2. <strong>Expert project design</strong> — engineers, planners, affected residents</p><p>3. <strong>Public visualization and impact analysis</strong> — AI-generated imagery (Measure 53b) for visual impact preview; GIS-based traffic, utility, and infrastructure analysis (Measure 53). Publish the analyses showing traffic, noise, visual impact, effects on adjacent streets and businesses. Let residents see the future before they decide</p><p>4. <strong>Referendum if a new capital project over $25M</strong> — binding public vote under statutory process (Measure 77)</p><p>5. <strong>Quarterly public progress reports</strong> during construction — on time, on budget, or explain why not</p><p>The Crystal Pool replacement (Feb 2025, 58.7% Yes, $168.9M borrowing) is the proof of concept. <strong>We will continue it as voted, and we will require the same process for every new capital project over $25M.</strong></p>", "budget": ""},
  {"id": "79", "pillar": "democratic", "section": "Direct Democracy and Transparency", "tier": "core", "title": "Close the feedback loop", "body": "<p>Every public consultation must report back: here's what you said, here's what we decided, here's why. Transparency isn't a value statement — it's a service standard. Too many consultations in Victoria end with a report that gathers dust. We will publish a response to every consultation within 60 days.</p>", "budget": ""},
  {"id": "79b", "pillar": "democratic", "section": "Direct Democracy and Transparency", "tier": "sub", "title": "Implement an Integrity Commissioner and the MNP governance report recommendations", "body": "<p>The MNP governance review of Victoria City Council surfaced specific recommendations on conflict-of-interest management, council-staff boundaries, transparency in decision-making, and the establishment of an <strong>Integrity Commissioner</strong> to investigate complaints against elected officials and recommend remedies. Implementation of those recommendations has lagged. Council members across the political spectrum have advocated for it — Coun. Gardiner most consistently (\"the MNP recommendations should be addressed before further major decisions\" — <em>Capital Daily</em>), Coun. Coleman (process-integrity advocate), Coun. Hammond (council-conduct accountability).</p><p>We will:</p><ul><li><strong>Establish an arm's-length Integrity Commissioner office</strong> for the City of Victoria, with jurisdiction over conflicts of interest, gifts and benefits, post-employment restrictions, and council code-of-conduct breaches. A shared-service model with one or more adjacent municipalities is acceptable and likely cheaper</li><li><strong>Publish a complete implementation tracker</strong> for the MNP governance report recommendations, with status and target completion dates for each</li><li><strong>Annual public report</strong> on Integrity Commissioner caseload, outcomes, and systemic recommendations</li></ul><p>This is not a partisan tool. An Integrity Commissioner protects councillors of every persuasion from frivolous attacks and protects the public from genuine misconduct in equal measure.</p>", "budget": "$200–300K/year for a shared-service Integrity Commissioner office. Cost is far less than the litigation, FOI battles, and reputational damage of unresolved governance complaints."},
  {"id": "80", "pillar": "democratic", "section": "Direct Democracy and Transparency", "tier": "core", "title": "Neighbourhood empowerment", "body": "<p>Strengthen support for neighbourhood associations in Fernwood, James Bay, Fairfield, Vic West, Hillside-Quadra, and every community. Small grants for community-led meetings. Expand \"My Great Neighbourhood\" program. Expand the Local Champions Program — train residents to lead engagement in their own communities. The people who live in a neighbourhood know it best.</p>", "budget": ""},
  {"id": "80b", "pillar": "democratic", "section": "Direct Democracy and Transparency", "tier": "sub", "title": "Non-English grant and consultation accessibility", "body": "<p>On the Kim 2022 platform plank, the City will make its grant applications and public consultations accessible in languages other than English. Implementation:</p><ul><li><strong>Grants:</strong> application forms, eligibility criteria, and reporting templates available in the most common non-English languages spoken in Victoria (per most recent Census), plus on-demand translation support</li><li><strong>Consultations:</strong> translated summaries and on-demand interpretation at major in-person consultations</li><li><strong>Neighbourhood associations:</strong> small grants top-up for associations that proactively translate and interpret</li><li><strong>Costs:</strong> modest — translation is now substantially aided by AI tooling, with human review for sensitive material</li></ul><p>This is accessibility, not ideology. Victoria's population is more linguistically diverse than its civic processes reflect, and the people who need municipal services most often have the least access to them.</p>", "budget": "$80–120K/year for translation tools, on-demand interpretation, and a neighbourhood-association top-up fund."},
  {"id": "81", "pillar": "democratic", "section": "Direct Democracy and Transparency", "tier": "core", "title": "An honest answer on Saanich amalgamation — binding Citizens' Assembly", "body": "<p>The question of whether Victoria and Saanich should merge has been live for over 20 years. Victorians and Saanich residents deserve a clear process to settle it — not a perpetual debate that drains political energy from both councils.</p><p><strong>Building on Coun. Chris Coleman's existing committee work.</strong> Coun. Coleman currently chairs Victoria's Citizens' Assembly Council Committee — the deliberative-democracy infrastructure for this kind of question already exists. Measure 81 is the natural extension of that work: take the Assembly model from advisory to binding, with cross-municipal participation.</p><p>We support a <strong>binding Citizens' Assembly model</strong>:</p><ul><li><strong>60 randomly selected residents</strong> (30 from each municipality), reflecting demographics by age, geography, and income</li><li><strong>12–18 months</strong> of paid expert input on fiscal, service delivery, governance, and identity considerations</li><li>A <strong>binding referendum question</strong> drafted by the Assembly itself</li><li>Both municipal councils pre-commit to <strong>honour the result</strong>, regardless of direction</li><li>Province requested to provide the statutory framework and funding support, as it did for the 2004 Citizens' Assembly on Electoral Reform</li></ul><p>This is how British Columbia handled electoral reform in 2004. It is mature, deliberative, and resistant to populist short-cuts in either direction. The status quo of selective consultation and political stalling fails residents who deserve a real answer.</p>", "budget": ""},
  {"id": "82", "pillar": "democratic", "section": "Direct Democracy and Transparency", "tier": "core", "title": "Annual community surveys", "body": "<p>Track satisfaction, priorities, and safety perceptions across every neighbourhood. Publish results. Adjust course. No governing in the dark.</p>", "budget": ""},
];
