const FAQ = [
  {q:"You're too pro-business / anti-environment",a:"This framework supports both. The framework includes 50% GHG reduction by 2030, 5,000 new trees, 60% green mobility, and Climate Friendly Homes expansion — with published uptake numbers, which the current council has not provided. That is not anti-environment. It is results-oriented environmentalism."},
  {q:"You're cutting services / austerity",a:"We are not cutting services — we are ensuring every dollar delivers value. Good management isn't austerity, it's responsibility. Every dollar saved through zero-based budgeting and competitive bidding gets redirected to frontline services: more bylaw officers, faster permits, cleaner streets, modern infrastructure."},
  {q:"You don't care about homelessness",a:"Compassion without accountability helps no one. This framework commits to a 50% reduction in unsheltered homelessness through Housing-First, supportive housing, wraparound services, and relentless advocacy to the Province. But we also enforce the rules — because residents, businesses, and vulnerable people themselves deserve safe, orderly public spaces. The phased implementation plan proves we understand you cannot enforce without capacity."},
  {q:"You just want to privatize everything",a:"We want competitive bidding for services where the private sector demonstrably delivers better results at lower cost — waste collection, street cleaning. Workers are protected with mandatory re-employment clauses. The City retains oversight and audits performance. The Phoenix \u201cmanaged competition\u201d model even lets City workers bid against private firms to keep services public when public delivery is competitive."},
  {q:"Referendums slow everything down",a:"Only new (non-lifecycle) capital projects over $25M go to referendum, within the BC statutory framework. Lifecycle maintenance is excluded so essential infrastructure work proceeds. That means a handful of major new-build decisions per term, not every speed bump and park bench. The Crystal Pool referendum (February 2025, 58.7% Yes) proved Victorians can make informed decisions on major spending."},
  {q:"You're going to put surveillance in our streetlights",a:"No. This framework explicitly rejects audio surveillance, behavioural AI, gunshot/scream detection, and any \u201cdirected brightness at suspect\u201d functionality on public streetlights. Measure 30 is the Kelowna/Halifax model: LED conversion, IoT-connected platform for outage detection and brightness modulation, optional environmental sensors. The crime-reduction benefit of streetlighting itself — ~21% per systematic-review evidence — is real and does not require any surveillance."},
  {q:"How does this differ from a candidate platform?",a:"This is a framework, not a campaign. It is open for adoption by any candidate, in whole or in part. Multiple candidates can run on these ideas, and they should. The goal is to raise the standard of debate — to make costed, sourced, measurable platforms with quarterly accountability the new normal in Victoria."}
];

function esc(s){return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");}
const $=(s,r)=>(r||document).querySelector(s);
const $$=(s,r)=>Array.from((r||document).querySelectorAll(s));

function renderPillars(){
  var c=$("#pgd"); if(!c) return; var h="";
  PILLAR_ORDER.forEach(function(k){
    var p=PILLARS[k];
    var n=MEASURES.filter(function(m){return m.pillar===k;}).length;
    h+='<a class="pc" data-pj="'+k+'" href="#measures" style="border-top:3px solid '+p.color+'">'+
       '<div class="pch"><span class="pce">'+p.emoji+'</span><span class="pct" style="color:'+p.color+'">'+n+' measures</span></div>'+
       '<div class="pti" style="color:'+p.color+'">'+esc(p.label)+'</div>'+
       '<div class="pd">'+esc(p.desc)+'</div>'+
       '<div class="pca" style="color:'+p.color+'">View measures <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></div>'+
       '</a>';
  });
  c.innerHTML=h;
  $$("[data-pj]").forEach(function(a){a.addEventListener("click",function(){setTimeout(function(){setFilter(a.getAttribute("data-pj"));},80);});});
}

function renderMeasures(){
  var c=$("#mctr"); if(!c) return; var h="";
  PILLAR_ORDER.forEach(function(pk){
    var p=PILLARS[pk];
    var items=MEASURES.filter(function(m){return m.pillar===pk;});
    if(!items.length) return;
    var sections=[]; items.forEach(function(m){ if(sections.indexOf(m.section)<0) sections.push(m.section); });
    var f=items[0].id, l=items[items.length-1].id;
    h+='<div class="pgr" data-pg="'+pk+'" style="border-top-color:'+p.color+'40">'+
       '<div class="pgh"><div class="pgt" style="color:'+p.color+'"><span style="font-size:1.1em">'+p.emoji+'</span> '+esc(p.label)+'</div>'+
       '<span class="pgg" style="color:'+p.color+'">'+items.length+' measures · M'+f+'–M'+l+'</span></div>';
    sections.forEach(function(sec){
      var sm=items.filter(function(m){return m.section===sec;});
      h+='<div><div class="shd">◆ '+esc(sec)+'</div>';
      sm.forEach(function(m){
        var tg=m.tier==="sub"?'<span class="mtg">Sub-measure</span>':"";
        var bu=m.budget?'<div class="mbu"><div class="mbl">Budget Impact</div><div class="mbx">'+m.budget+'</div></div>':"";
        var search=(m.title+" "+m.body+" "+(m.budget||"")+" M"+m.id+" "+m.section).toLowerCase().replace(/<[^>]+>/g," ");
        h+='<article class="mi mit" data-p="'+pk+'" data-s="'+esc(search)+'">'+
           '<div class="mnu">M'+esc(m.id)+'</div>'+
           '<div class="mb2"><h3 class="mti" style="color:'+p.color+'">'+esc(m.title)+tg+'</h3>'+
           '<div class="mbody">'+m.body+'</div>'+bu+'</div>'+
           '</article>';
      });
      h+='</div>';
    });
    h+='</div>';
  });
  c.innerHTML=h;
}

var cf="all", cs="";
function applyFilters(){
  var v=0;
  $$(".mit").forEach(function(el){
    var po=cf==="all"||el.getAttribute("data-p")===cf;
    var so=!cs||el.getAttribute("data-s").indexOf(cs)>=0;
    if(po&&so){el.classList.remove("hbf");v++;}else{el.classList.add("hbf");}
  });
  $$("[data-pg]").forEach(function(g){
    var has=g.querySelectorAll(".mit:not(.hbf)").length;
    g.style.display=has?"":"none";
  });
  var mc=$("#mcount"); if(mc) mc.textContent=v+" measure"+(v===1?"":"s");
}
function setFilter(k){
  cf=k;
  $$(".cp").forEach(function(c){c.classList.toggle("a",c.getAttribute("data-f")===k);});
  applyFilters();
}
function setupFilters(){
  $$(".cp").forEach(function(c){c.addEventListener("click",function(){setFilter(c.getAttribute("data-f"));});});
  var s=$("#ms"); if(s) s.addEventListener("input",function(e){cs=e.target.value.trim().toLowerCase();applyFilters();});
}

function renderScorecard(){
  var tb=$("#ctbl"); if(!tb) return; var t="", c="";
  COMMITMENTS.forEach(function(x){
    t+='<tr><td class="cnu">'+x.n+'</td><td class="ccm">'+esc(x.c)+'</td><td>'+esc(x.t)+'</td><td class="cba">'+esc(x.b)+'</td></tr>';
    c+='<div class="scc"><div class="scr"><div class="scn">'+x.n+'</div><div class="scl">'+esc(x.c)+'</div></div><div class="sme"><strong>Target:</strong> '+esc(x.t)+'</div><div class="sme"><strong>Baseline:</strong> '+esc(x.b)+'</div></div>';
  });
  tb.innerHTML=t;
  var cc=$("#ccrd"); if(cc) cc.innerHTML=c;
}

function renderFaq(){
  var c=$("#fqc"); if(!c) return; var h="";
  FAQ.forEach(function(i){
    h+='<details class="fqi"><summary class="fqs"><span class="fqq">"'+esc(i.q)+'"</span>'+
       '<span class="fqp"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg></span></summary>'+
       '<div class="fqa">'+esc(i.a)+'</div></details>';
  });
  c.innerHTML=h;
}

function setupJump(){
  var b=$("#jb"),d=$("#jdr"),bd=$("#jbd"),cl=$("#jcl");
  if(!b||!d) return;
  function op(){d.classList.add("o");bd.classList.add("o");}
  function sh(){d.classList.remove("o");bd.classList.remove("o");}
  b.addEventListener("click",op); cl.addEventListener("click",sh); bd.addEventListener("click",sh);
  $$(".jl").forEach(function(a){a.addEventListener("click",function(){setTimeout(sh,80);});});
  var tk=false;
  window.addEventListener("scroll",function(){
    if(tk)return; tk=true;
    requestAnimationFrame(function(){ b.classList.toggle("hd",window.scrollY<=600); tk=false; });
  },{passive:true});
}

function checkSubscribed(){
  if(new URLSearchParams(window.location.search).get("subscribed")==="true"){
    var s=$("#smg"); if(s) s.classList.add("sh");
  }
}

document.addEventListener("DOMContentLoaded",function(){
  renderPillars(); renderMeasures(); renderScorecard(); renderFaq();
  setupFilters(); setupJump(); checkSubscribed();
});
